window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q02"]=window.__LIBQ["the-gioi-hoan-my"]["q02"]||{};window.__LIBQ["the-gioi-hoan-my"]["q02"]["artifacts"]={"updatedAt":"2026-07-04","count":225,"artifacts":[{"id":"bach-cot-dai-bong","name":"Bạch cốt đại bổng","aliases":["Búa (của nhóc tỳ)"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Cây gậy lớn bằng xương trắng của Nhóc tỳ, dùng như búa để tập kích.","detail":"Bạch cốt đại bổng là cây gậy lớn bằng xương trắng của Nhóc tỳ (Thạch Hạo), dùng giống như một cây búa để tập kích bất ngờ. Trong đòn đánh lén cuối chương, Nhóc tỳ từ cây gỗ khô sau lưng Tiêu Thiên nứt ra, giáng hai búa liên tiếp vào sau gáy, quật ngã kẻ mạnh nhất hơn chín vạn người — trở thành đòn tủ hạ gục cường giả của lối đánh du kích ẩn thân.","nguon":["@c0101"]},{"id":"bo-thien-thach","name":"Bổ Thiên thạch","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Tiêu Thiên"],"trangThai":"dang-co","blurb":"Vật phẩm nhiệm vụ mà thí sinh phải cướp đoạt để đạt yêu cầu vượt qua đợt kiểm tra của Bổ Thiên các.","detail":"Bổ Thiên thạch là thứ thí sinh phải cướp đoạt để đạt yêu cầu thấp nhất vượt qua đợt kiểm tra tại chiến trường thứ hai. Kẻ bại trận bị cướp sạch, còn Tiêu Thiên một đêm chinh chiến thu được 16 khối. Nhóc tỳ cũng quay lại chiến trường tan hoang để đoạt thêm.","nguon":["@c0101"]},{"id":"bao-dan-tieu-thien","name":"Bảo đan","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Tiêu Thiên"],"trangThai":"da-dung","blurb":"Đan dược hồi phục Tiêu Thiên nuốt để khôi phục trạng thái cường thịnh sau ác chiến.","detail":"Viên bảo đan Tiêu Thiên nuốt sau đại chiến khiến toàn thân sáng lên, khôi phục về trạng thái cường thịnh nhanh chóng.","nguon":["@c0101"]},{"id":"bao-dan-bo-tinh-tri-thuong","name":"Bảo đan (bổ tinh huyết & trị trọng thương)","category":"dan-duoc","categoryLabel":"Đan dược","soHuu":["Tiêu Thiên","Thạch Hạo"],"trangThai":"dang-co","blurb":"Hai bình bảo đan quý giá, một loại bổ sung tinh huyết, một loại trị liệu trọng thương.","detail":"Hai bình bảo đan Tiêu Thiên mang theo: một loại bổ sung tinh huyết, một loại trị liệu trọng thương, rất có giá trị. Nhóc tỳ lấy được từ người Tiêu Thiên khi lục soát.","nguon":["@c0102"]},{"id":"de-tu","name":"Đế tử","category":"khac","categoryLabel":"Vật phẩm","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Một Đế tử nhỏ như sợi tóc, được mô tả là rất đáng tiền.","detail":"Một vật nhỏ như sợi tóc, rất đáng giá, trước đó khi tìm bảo vật đã bị bỏ sót, nay được Nhóc tỳ tiện tay thu lại.","nguon":["@c0102"]},{"id":"long-tan","name":"Long Tán","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"Đã tặng cho hai huynh muội","blurb":"Một viên đan cường gân tráng cốt, khôi phục nguyên khí trong nháy mắt.","detail":"Đan dược quý cường gân tráng cốt, giúp khôi phục nguyên khí trong nháy mắt. Vốn là chiến lợi phẩm nhóc tỳ lột được từ thiếu niên áo bạc (Tiêu Thiên); trước khi chia tay, nhóc tỳ tặng mỗi người trong hai huynh muội một viên rút ra từ hai bình thuốc quý cùng với Hổ Dược.","nguon":["@c0103"]},{"id":"ho-duoc","name":"Hổ Dược","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"Đã tặng cho hai huynh muội","blurb":"Đan dược trị thương công hiệu thần kỳ, rất quý.","detail":"Đan dược quý dùng để trị thương, công hiệu thần kỳ. Cũng là chiến lợi phẩm nhóc tỳ lột được từ thiếu niên áo bạc (Tiêu Thiên); được tặng cho hai huynh muội cùng với Long Tán từ hai bình thuốc quý.","nguon":["@c0103"]},{"id":"bua-cua-nhoc-ty","name":"Búa của nhóc tỳ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"Đang sử dụng","blurb":"Vũ khí búa nhóc tỳ dùng đánh lén, từng gõ ngất Tiêu Thiên hai búa vào cùng một chỗ.","detail":"Vũ khí búa của nhóc tỳ, dùng để đánh lén khiến thiếu niên áo bạc (Tiêu Thiên) ngất cả đêm; hai phát búa trúng cùng một chỗ trên trán Tiêu Thiên khiến hắn mọc một cục u to như sừng. Nhóc tỳ tự gắn danh hiệu với vũ khí này qua câu khắc trên đá “Búa ở trong tay, thiên hạ ta có”.","nguon":["@c0103"]},{"id":"hac-ho-sat","name":"Hắc Hổ Sát","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Bổ Thiên Các"],"trangThai":"Được dùng chăm bón gốc thuốc quý","blurb":"Chất bồi dưỡng quý dùng chăm bón gốc thuốc của Bổ Thiên Các.","detail":"Chất bồi dưỡng quý được Bổ Thiên Các dùng để chăm bón một gốc thuốc quý; nhờ nuôi bằng Hắc Hổ Sát, gốc thuốc ấy tương lai có thể lột xác thành Thánh Dược. Trác Vân trưởng lão mời khách “xem lễ” thưởng thức để phô nội tình tông môn, oai chấn tứ phương.","nguon":["@c0103"]},{"id":"goc-thuoc-thanh-duoc","name":"Gốc thuốc quý (tiềm năng Thánh Dược)","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Bổ Thiên Các"],"trangThai":"Đang được nuôi dưỡng","blurb":"Bảo vật của Bổ Thiên Các, nuôi bằng Hắc Hổ Sát, tương lai có thể lột xác thành Thánh Dược.","detail":"Một gốc thuốc quý được Bổ Thiên Các chăm bón bằng Hắc Hổ Sát; tương lai có tiềm năng lột xác thành Thánh Dược. Trác Vân trưởng lão đem ra mời khách thưởng thức nhằm phô nội tình tông môn.","nguon":["@c0103"]},{"id":"bao-cot-bo-thien-cac","name":"Bảo cốt","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Mười tám bộ bảo cốt sáng óng ánh nhóc tỳ giấu ở chiến trường thứ hai.","detail":"Mười tám bộ bảo cốt sáng óng ánh mà nhóc tỳ giấu ở chiến trường thứ hai; Bổ Thiên các chỉ tìm được sáu bộ (ba bộ trong tổ chim con, ba bộ sau thác nước), còn mười hai bộ chưa bị phát hiện.","nguon":["@c0105"]},{"id":"da-thu-co-phu-van","name":"Da thú cổ lấp lánh phù văn","category":"phap-bao","categoryLabel":"Pháp bảo vận chuyển","soHuu":["Bổ Thiên các"],"trangThai":"dang-co","blurb":"Tấm da thú cổ có phù văn, bay cách mặt đất hơn một mét, dùng chở cường giả và bảo vật.","detail":"Bay tới sơn môn Bổ Thiên các mang theo cường giả cùng tảng đá Tế Linh có chữ khiêu khích của Nhóc siêu quậy trong nghi thức nhập môn.","nguon":["@c0106"]},{"id":"xich-giao-dang","name":"Xích Giao đằng","category":"nguyen-lieu","categoryLabel":"Linh dược","blurb":"Linh dược dạng dây dài hơn hai mét trong Thượng cổ Tịnh Thổ.","detail":"Loại linh dược dạng dây leo dài mà Thạch Hạo nhòm ngó muốn chặt một khúc khi vừa vào sơn môn Bổ Thiên các.","nguon":["@c0106"]},{"id":"hoa-linh-tuoc","name":"Hỏa Linh tước","category":"khac","categoryLabel":"Linh cầm","blurb":"Bầy chim linh béo mập trong Thượng cổ Tịnh Thổ.","detail":"Loài linh cầm béo mập bay lượn trong sơn môn Bổ Thiên các mà Thạch Hạo thèm ăn ngay khi vừa nhập môn.","nguon":["@c0106"]},{"id":"duoc-tan","name":"Dược Tán","category":"dan-duoc","categoryLabel":"Đan dược","soHuu":[],"blurb":"Đan dược quý hiếm thiên tài doanh phát đầu tháng, giúp tu vi tăng nhanh.","detail":"Đầu mỗi tháng thiên tài doanh Bổ Thiên các phát Dược Tán cho đệ tử ưu tú; chính là mục tiêu Thanh Phong quyết cắn răng kiên trì để nhận được.","nguon":["@c0107","@c0113"]},{"id":"ho-lo-vo-vang-bo-thien-cac","name":"Hồ lô vỏ vàng","cn":"","aliases":["Chí bảo Bổ Thiên các"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo","soHuu":["Ông lão cầm hồ lô vỏ vàng"],"trangThai":"dang-co","blurb":"Chí bảo Bổ Thiên các do Tế Linh kết ra, nuốt hết bão táp hủy diệt vùng núi.","detail":"Hồ lô màu vàng óng toả ra hi quang, trên thân chỉ có một Phù Văn giống khai thiên lập địa khiến vạn linh run rẩy, có khí Hỗn Độn bao phủ. Từ hư không xuất hiện, nuốt hết bão táp mãnh liệt đủ hủy diệt một vùng núi như cá voi hút nước, rồi thu nhỏ bằng lòng bàn tay. Là chí bảo của Bổ Thiên các do Tế Linh (một giàn dây hồ lô) kết ra.","nguon":["@c0109"]},{"id":"ho-lo-vo-xanh","name":"Hồ lô vỏ xanh","cn":"","aliases":["Trái hồ lô màu xanh"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tế Linh"],"trangThai":"dang-co","blurb":"Trái hồ lô màu xanh trên giàn dây hồ lô khô vàng của Tế Linh; khi bị tiếp cận phát khí Hỗn Độn.","detail":"Nằm trên giàn dây hồ lô khô vàng ở Thượng Cổ Tịnh Thổ. Khi Thạch Hạo vọt lên định chạm để đánh thức Tế Linh, hồ lô phát ra khí Hỗn Độn, đạo âm chấn động, hiển hóa Phù Văn ngàn tia vạn sợi, khí thế như thời chưa khai thiên lập địa, đẩy lui nó.","nguon":["@c0111"]},{"id":"co-kiem-thuong-co","name":"Cổ kiếm Thượng Cổ","cn":"","aliases":["Cổ kiếm cắm trên đầu ông lão"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tử Thần"],"trangThai":"dang-co","blurb":"Thanh cổ kiếm rỉ sét cắm trên đầu ông lão tử khí Thượng Cổ; tỏa sát khí, phát tiếng rung, tràn ra máu đen.","detail":"Kiếm vốn sắc bén nay rỉ sét loang lổ, cắm trên đầu ông lão tóc xám. Khi ông lão đòi trả kiếm, thanh kiếm phát tiếng rung, tràn ra vết máu đen. Thanh kiếm dường như bám theo sinh vật khiến nó muốn đập gãy để thoát.","nguon":["@c0111"]},{"id":"ho-lo-vang-hon-don","name":"Hồ lô vàng óng","cn":"","aliases":["Hồ lô vỏ vàng (Đào Dã)","Hồ lô vàng óng (Đào Dã)","Hồ lô vỏ vàng (chí bảo Bổ Thiên các)"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Ông lão cầm hồ lô vỏ vàng"],"trangThai":"dang-co","blurb":"Cái hồ lô vàng óng ông lão phương xa nâng trên tay, tràn ngập khí Hỗn Độn.","detail":"Cùng lúc có tiếng phá không vang tới, một ông lão xuất hiện từ phương xa, tay nâng một cái hồ lô vàng óng tràn ngập khí Hỗn Độn, gợi lai lịch bất phàm chưa rõ.","nguon":["@c0111","@c0112","@c0109"]},{"id":"co-kiem-cam-dau-tu-than","name":"Cổ kiếm cắm đầu Tử Thần","category":"than-khi","categoryLabel":"Thần khí","soHuu":["Tử Thần"],"trangThai":"dang-co","blurb":"Thanh cổ kiếm đâm xuyên đầu Tử Thần, cực bền không sứt mẻ; là kiếm của đối thủ ngày xưa chứ không phải của Hắn.","detail":"Thanh kiếm đâm xuyên đầu vị thần quái Thượng Cổ, cực kỳ bền chắc; nhóc tỳ dùng đỉnh đồng gõ leng keng đốm lửa tứ tung mà đầu lâu lẫn kiếm đều không sứt mẻ. Đào Dã tiết lộ đây không phải kiếm của Tử Thần mà của đối thủ ngày xưa; kiếm thật của Tử Thần rơi mất ở Bách Đoạn sơn mạch.","nguon":["@c0112"]},{"id":"nguyen-thuy-bao-cot","name":"Nguyên Thủy Bảo Cốt","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Bổ Thiên các"],"trangThai":"dang-co","blurb":"Bảo vật đặt trong đại điện nghị sự Bổ Thiên các, Phù Văn lưu chuyển gia trì bắn ra từng tia thần hi.","detail":"Đặt trong đại điện nghị sự của Bổ Thiên các trên ngọn núi cao khảm kỳ thạch phát sáng; Phù Văn lưu chuyển gia trì, bắn ra từng tia thần hi, nơi bàn sự kiện trọng đại như nhiệm vụ Bách Đoạn sơn.","nguon":["@c0112"]},{"id":"bat-lao-than-tuyen","name":"Bất Lão thần tuyền","category":"khac","categoryLabel":"Kỳ vật","soHuu":[],"trangThai":"dang-co","blurb":"Suối thần nằm nơi bí mật trong Bách Đoạn sơn, mục tiêu nhiệm vụ của nhóc tỳ.","detail":"Thần tuyền nằm nơi bí mật trong Bách Đoạn sơn, điều kiện tới gần vô cùng tồi tệ; muốn đến gần phải phá Phù Văn của Thượng Cổ Thánh trận. Bốn lão tiền bối Bổ Thiên các giao Thạch Hạo tìm mang về, ai lập được công sẽ được khắc tên lên Bất Hủ Thần Bi.","nguon":["@c0113","@c0125"]},{"id":"tuyet-ngoc-sam","name":"Tuyết Ngọc Sâm","category":"dan-duoc","categoryLabel":"Linh dược","soHuu":[],"trangThai":"da-dung","blurb":"Cây nhân sâm trắng như ngọc mọc ở cửa cung điện Bổ Thiên các.","detail":"Linh dược quý mọc ở cửa cung điện Bổ Thiên các. Nhóc tỳ Thạch Hạo trộm gặm ăn rồi khai Đào Dã cho — thực ra nó chỉ hỏi cây củ cải ở vườn rau có ăn được không và Đào Dã gật đầu.","nguon":["@c0113"]},{"id":"bat-hu-than-bi","name":"Bất Hủ Thần Bi","category":"khac","categoryLabel":"Bia thần","soHuu":[],"trangThai":"dang-co","blurb":"Bia của Bổ Thiên các, ai lập công sẽ được khắc tên lên.","detail":"Bia thần của Bổ Thiên các; ai mang được Bất Lão thần tuyền về sẽ được khắc tên lên bia này như một vinh dự.","nguon":["@c0113"]},{"id":"linh-duoc-tang-thanh-phong","name":"Linh Dược (tặng Thanh Phong)","category":"dan-duoc","categoryLabel":"Đan dược","soHuu":["Thanh Phong"],"trangThai":"dang-co","blurb":"Một cây linh dược nguyên vẹn tỏa sáng, quý hơn Dược tán.","detail":"Một cây linh dược nguyên vẹn tỏa sáng, quý hơn Dược tán mà đệ tử thiên tài thường dùng. Nhóc tỳ tặng cho đệ đệ Thanh Phong ở Thiên tài doanh, nói là tiền cược thắng hậu duệ một Thái Cổ di chủng, sau lấy làm vật ván cược khiêu chiến.","nguon":["@c0113"]},{"id":"tang-than","name":"Tang thần","category":"khac","categoryLabel":"Vật theo người","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Thứ mang bên người nhóc tỳ khiến nó buộc phải nghe theo.","detail":"Thứ mang bên người Thạch Hạo mà Đào Dã dọa nếu không đi Bách Đoạn sơn thì Hắn không đáp ứng và nó sớm muộn mất mạng. Danh tính thế lực bí ẩn liên quan chưa lộ.","nguon":["@c0113"]},{"id":"thien-cot","name":"Thiên Cốt","category":"khac","categoryLabel":"Kỳ vật","soHuu":[],"trangThai":"dang-co","blurb":"Xương thần có thể tìm được ở Bách Đoạn sơn.","detail":"Một trong các cơ duyên của Bách Đoạn sơn, xương thần được nêu bên cạnh truyền thừa Chư Thánh và thánh dược.","nguon":["@c0113"]},{"id":"ho-lo-xanh-khai-lo","name":"Hồ lô màu xanh","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Các trưởng lão Bổ Thiên các"],"trangThai":"dang-co","blurb":"Hồ lô màu xanh khai lộ, dựng thành thông đạo xanh cho đoàn người rời Bổ Thiên các.","detail":"Trong một mảnh hào quang, hồ lô màu xanh hiện lên lắc lư không ngừng, dựng thành một con đường màu xanh (thông đạo). Đoàn đệ tử Bổ Thiên các đi vào thông đạo và toàn bộ biến mất khỏi Bổ Thiên các, hướng tới điểm đến bí ẩn.","nguon":["@c0114"]},{"id":"cot-thu-doan-khong-thanh","name":"Cốt Thư (bày bán Đoạn Không thành)","category":"khac","categoryLabel":"Vật phẩm","trangThai":"dang-co","blurb":"Loại sách cốt thư được bày bán trong Đoạn Không thành cùng binh khí, dược thảo, xương thú.","detail":"Trong cửa hàng ở Đoạn Không thành bày bán nhiều vật thiết yếu: xương thú trân quý, dược thảo cao tuổi, binh khí và Cốt Thư.","nguon":["@c0115"]},{"id":"xe-keo-rem-ngoc-thach","name":"Xe kéo rèm ngọc thạch","category":"khac","categoryLabel":"Vật phẩm","trangThai":"dang-co","blurb":"Xe của tiểu Bạch Hổ, rèm ghép từ chuỗi ngọc thạch, do hung thú kéo.","detail":"Xe kéo do phu xe Nhân tộc và hung thú kéo, rèm ghép từ chuỗi ngọc thạch; trong xe là con tiểu Bạch Hổ Thái Cổ dị chủng, hai cô gái hầu hạ cho ăn thịt.","nguon":["@c0115"]},{"id":"dai-hoang-kinh","name":"Đại Hoang kinh","cn":"","category":"khac","categoryLabel":"Sách cổ","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Sách cổ chuyên giới thiệu các loại sinh linh mà nhóc tỳ từng đọc, có ghi chép về Phì Di.","detail":"Sách chuyên giới thiệu các chủng loại sinh linh trong thiên hạ. Nhờ đọc qua Đại Hoang kinh mà nhóc tỳ nhận ra được các dị chủng như Thái Cổ di chủng Phì Di.","nguon":["@c0116"]},{"id":"bao-tai-bao-boi-nha-bep","name":"Bao tải “bảo bối” (nồi niêu xoong chảo)","category":"khac","categoryLabel":"Khác","phamCap":"Phàm phẩm","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Bao tải to Thạch Hạo khoe là “bảo bối”, thực chất là nồi niêu xoong chảo, gia vị “trưng dụng” cả một nhà bếp môn phái.","detail":"Thạch Hạo vác một bao tải to như chuyển nhà, khoe với đám dị tộc là toàn bảo bối; khi mở ra lộ nồi niêu xoong chảo cùng gia vị — cả một nhà bếp bị dọn sạch, có ghi chú tên môn phái, mang vào Bách Đoạn Sơn để sinh tồn nơi hoang dã.","nguon":["@c0117"]},{"id":"bon-goc-linh-duoc-bach-doan-son","name":"Bốn gốc linh dược (vách núi Bách Đoạn Sơn)","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Linh dược","soHuu":[],"trangThai":"dang-co","blurb":"Bốn gốc linh dược sư tỷ Bổ Thiên các phát hiện trên một vách núi trong tiểu thế giới Bách Đoạn Sơn.","detail":"Sư tỷ trong nhóm Bổ Thiên các phát hiện bốn gốc linh dược mọc trên một vách núi giữa tiểu thế giới linh khí đậm đặc của Bách Đoạn Sơn.","nguon":["@c0117"]},{"id":"xich-lan","name":"Xích Lan","category":"linh-khi","categoryLabel":"Linh dược","phamCap":"","soHuu":["Sinh vật hình người ánh bạc"],"trangThai":"bi-cuop","blurb":"Bốn gốc linh dược mọc dàn hàng trên vách núi bên hồ, hình như lưỡi khoan đỏ như máu, nghi giúp đột phá bình cảnh.","detail":"Linh dược quý hiếm: bốn gốc mọc dàn hàng trên vách núi bên hồ trong tiểu thế giới, hình như lưỡi khoan đỏ như máu, có luân văn màu đỏ máu, nghi giúp đột phá bình cảnh. Bị sinh vật hình người ánh bạc ngắt cả bốn gốc.","nguon":["@c0118"]},{"id":"cot-kinh-toan-nghe","name":"Cốt Kính (bảo cốt Toan Nghê)","aliases":["Bảo kính Toan Nghê","cốt kính trắng"],"category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"chí bảo (luyện từ Bảo Cốt Toan Nghê)","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Gương xương trong suốt như ngọc luyện từ Bảo Cốt Toan Nghê; phản chiếu ánh sáng, mặt ngược khắc Phù Văn thôi thúc tia chớp vàng.","detail":"Cốt Kính là Bảo Cụ Thạch Hạo liều mạng đoạt về, tế luyện từ Bảo Cốt của Toan Nghê — loại Thái Cổ di chủng mạnh nhất. Phản chiếu ánh sáng bạc của đối thủ khiến bả vai thủng hai lỗ máu; mặt ngược khắc Phù Văn thôi thúc hàm nghĩa Toan Nghê phóng tia chớp vàng; còn nâng chân Thạch Hạo khi truy đuổi (tiêu hao Tinh Khí Thần) và đánh đầu lâu đối thủ thành tro.","nguon":["@c0119"]},{"id":"cot-tien-mau-vang","name":"Cốt Tiễn màu vàng","aliases":["Kim Giao tiễn","Long Giao tiễn","Cốt Tiễn vàng kim","Cốt Tiễn mùa vàng"],"category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"chí bảo (cốt bảo)","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Mũi tên xương ghép từ hai mảnh xương vàng, phát tiếng rồng gầm, có miệng núi lửa và dung nham.","detail":"Bảo Cụ thứ ba của Thạch Hạo, tạo thành từ hai mảnh xương màu vàng liên kết với nhau, phát tiếng rồng gầm và xuất hiện miệng núi lửa/dung nham. Bẻ gãy chủy thủ bạc, cắt đứt cánh tay trái rồi cắt cổ sinh linh màu bạc. Cũng do Thạch Hạo liều mạng đoạt về, không phải tộc nhân ban.","nguon":["@c0119","@c0134"]},{"id":"cay-quat-mau-bac","name":"Cây quạt màu bạc","aliases":["bảo phiến bạc","Quạt bạc rách nát"],"category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ","soHuu":["Sinh linh màu bạc","Thạch Hạo"],"trangThai":"hong","blurb":"Quạt xương bạc của sinh linh màu bạc, phun ra tạo sóng bạc san bằng núi rừng; bị Thạch Hạo cướp và hủy hơn nửa.","detail":"Bảo phiến bạc phun ra hóa thành, tạo sóng bạc san bằng dãy núi phía sau, uy lực cực lớn. Sau khi giết chủ, Thạch Hạo lấy làm chiến lợi phẩm nhưng nó đã nát hơn nửa, khiến Thạch Hạo bi phẫn tiếc nuối hơn cả bảo bối của mình.","nguon":["@c0119","@c0130"]},{"id":"chuy-thu-mau-bac","name":"Chủy thủ màu bạc","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ","soHuu":["Sinh linh màu bạc"],"trangThai":"hong","blurb":"Dao găm xương bạc mài từ Bảo Cốt, phun ra như đòn thứ ba của sinh linh màu bạc.","detail":"Chủy thủ bạc mài từ Bảo Cốt, được sinh linh màu bạc phun ra như đòn thứ ba, dùng quạt kiềm Cốt Kính; bị Cốt Tiễn vàng xoắn đứt làm hai đoạn.","nguon":["@c0119"]},{"id":"xe-phuong-may-do","name":"Xe phượng mây đỏ","aliases":["xe kéo mây đỏ","xe phượng"],"category":"phap-bao","categoryLabel":"bảo vật","phamCap":"bảo vật","soHuu":["Hỏa Linh Nhi"],"trangThai":"dang-co","blurb":"Xe kéo của con gái nhỏ Nhân Hoàng, lượn lờ mây đỏ, lấp loé hào quang đỏ thẫm, được hơn bốn mươi thiên tài hộ tống.","detail":"Chiếc xe kéo lấp loé hào quang đỏ thẫm, lượn lờ mây đỏ, được hơn bốn mươi thiên tài bảo vệ; Thạch Hạo từng thấy trên đường đi Bổ Thiên các. Là bảo vật của con gái nhỏ Nhân Hoàng.","nguon":["@c0119"]},{"id":"tu-van-tam","name":"Tử Vân Tâm","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Trái tim của Tử Vân Điêu, một Thái Cổ di chủng hung mãnh, giống viên bảo thạch màu tím to lớn rực rỡ.","detail":"Vật thể màu tím lớn bằng đầu người, óng ánh như kim cương tím, tỏa tử khí và hương thơm nức; dược hiệu bá đạo, có tác dụng lớn trong đột phá. Nhóc tỳ đổi con Linh Tộc màu bạc để lấy, rồi luyện hóa trong hang cổ để mở Động Thiên thứ bảy.","nguon":["@c0120"]},{"id":"sinh-vat-mau-bac-linh-toc","name":"Sinh linh màu bạc (Linh Tộc)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":[],"trangThai":"bi-cuop","blurb":"Con Linh Tộc toàn thân màu bạc có Vương huyết truyền thừa, Thái Cổ di chủng cực hiếm.","detail":"Con Linh Tộc toàn thân màu bạc, có Vương huyết truyền thừa; đồn có linh huyết hiếm do linh tính ngưng tụ (không phải huyết mạch), rèn ra được thì giúp người ngộ đạo. Bị nhóc tỳ chém giết rồi đem trao đổi lấy Tử Vân Tâm.","nguon":["@c0120"]},{"id":"dinh-ngoc-hinh-vuong","name":"Đỉnh ngọc hình vuông","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Đỉnh ngọc dài một thước dùng đựng Tử Vân Tâm.","detail":"Đỉnh ngọc hình vuông dài một thước người áo đen dùng đựng Tử Vân Tâm, mở ra thấy vật thể màu tím, tử khí lưu chuyển. Nhóc tỳ kiểm tra kỹ rồi cất giữ.","nguon":["@c0120"]},{"id":"chuoi-niem-chau-vang","name":"Chuỗi niệm châu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo Cụ","soHuu":["Sư Tử chín đầu"],"trangThai":"dang-co","blurb":"Bảo Cụ của Hoàng Kim sư tử, như chế từ vàng ròng, hào quang trấn áp, được phun ra để chống lại Cốt Tiễn của Nhóc tỳ.","detail":"Chuỗi niệm châu màu vàng như chế từ vàng ròng, tỏa hào quang trấn áp. Khi bị Cốt Tiễn của Nhóc tỳ làm trọng thương, Hoàng Kim sư tử phun ra chuỗi niệm châu này để chống đỡ, hai bảo vật va chạm dữ dội.","nguon":["@c0122"]},{"id":"cot-tien-long-giao","name":"Cốt Tiễn màu vàng (Long Giao tiễn)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Vượt xa cấp bậc bản thân","soHuu":["Nhóc tỳ"],"trangThai":"Nhóc tỳ đang sử dụng","blurb":"Tiễn xương màu vàng của nhóc tỳ, hóa hai giao long chém rụng đầu lâu Sư Tử chín đầu.","detail":"Cốt Tiễn màu vàng, còn gọi là Long Giao tiễn, là tiễn xương của nhóc tỳ. Khi xuất trận khẽ kêu “keng”, hóa thành hai giao long chém rụng bốn đầu lâu Sư Tử chín đầu (hai đầu bên trái rồi hai đầu bên phải). Uy lực vượt xa cấp bậc bản thân Sư Tử chín đầu, khiến sinh linh huyết thống cao quý này không thể lấy bảo thuật cứng rắn mà chống đỡ.","nguon":["@c0123"]},{"id":"chin-rang-nanh-niem-chau-su-tu","name":"Chín răng nanh vàng + niệm châu (bảo cụ Sư Tử chín đầu)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Vượt cấp bậc bản thân","soHuu":["Sư Tử chín đầu (Hoàng Kim sư tử)"],"trangThai":"Sư Tử chín đầu thu về bỏ trốn","blurb":"Bảo cụ của Sư Tử chín đầu: chín răng nanh vàng hóa phi kiếm và chín hạt niệm châu như thế giới nhỏ.","detail":"Bảo cụ của Sư Tử chín đầu (Hoàng Kim sư tử): chín thanh răng nanh màu vàng có thể hóa thành phi kiếm bổ vào đối thủ, cùng chuỗi niệm châu chín hạt — mỗi hạt lóng lánh như một thế giới nhỏ, sương mù lượn quanh, trấn áp đối thủ như đối kháng cả một mảnh thế giới. Cả hai đều vượt cấp bậc bản thân nó. Khi bại trận Sư Tử thu bảo cụ bỏ trốn; nhóc tỳ đuổi theo đòi “trả lại bảo cụ”.","nguon":["@c0123"]},{"id":"bao-duoc-dau-su-tu","name":"Bảo dược đầu sư tử (Huyết dược đầu sư tử)","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Lò bảo dược chứa thần tính","soHuu":["Nhóc tỳ","Bổ Thiên các"],"trangThai":"Đã hầm và ăn hết","blurb":"Bốn đầu lâu Sư Tử chín đầu hầm với bốn cây linh dược thành lò bảo dược chứa thần tính.","detail":"Bốn đầu lâu Sư Tử chín đầu (nơi chứa thần tính, tinh khí thần, sức mạnh màu vàng cực lớn) được nhóc tỳ hầm trong đỉnh đồng bên bờ sông một canh giờ, thêm bốn cây linh dược hái bên hồ để dược tính mạnh thêm. Kết quả là một lò bảo dược khó có thể tưởng tượng. Ăn vào thất khiếu phát sáng, cảm giác phun ra lửa. Nhóc tỳ ăn hết hai đầu cùng hơn nửa đỉnh chất lỏng; năm thiên tài Bổ Thiên các ăn nửa cái đầu lâu, vận Phù Văn tu hành và lần lượt đột phá sau nửa đêm.","nguon":["@c0123"]},{"id":"trung-vang-lang-than","name":"Trứng vàng (nghi hậu duệ Lang Thần)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Nghi hậu duệ Lang Thần","soHuu":["Hỏa Linh Nhi (đoạt được)","Nhóc tỳ (cướp lấy)"],"trangThai":"Bị nhóc tỳ cướp mang đi","blurb":"Quả trứng vàng to bằng chậu nước, khớp chữ khắc vách tường, nghi là hậu duệ của Lang Thần.","detail":"Quả trứng vàng to bằng chậu nước, tỏa ánh sáng, khớp với chữ khắc trên vách tường Ma Quật về hậu duệ Lang Thần. Hỏa Linh Nhi đoạt được từ trong Ma Quật; khi túi da của người đội nón lá vỡ, trứng rơi ra, các thế lực (Sư Tử chín đầu, Ngân Huyết, Vũ Vương, Hỏa Linh Nhi cùng thiên tài Nhân tộc) đều tranh cướp. Nhóc tỳ vọt tới ôm chặt, đòi luộc ăn rồi xông qua bầy sói biến mất.","nguon":["@c0123"]},{"id":"dau-lau-vang-than-tinh","name":"Đầu lâu màu vàng (thần tính)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Bao hàm lực lượng thần tính","soHuu":["Sư Tử chín đầu (nguồn gốc)"],"trangThai":"Đã hầm làm bảo dược","blurb":"Đầu lâu Sư Tử chín đầu thực chất là chất lỏng đậm đặc và thịt màu vàng bao hàm lực lượng thần tính.","detail":"Đầu lâu màu vàng của Sư Tử chín đầu không có xương thật, gồm chất lỏng đậm đặc và thịt màu vàng thơm nức, bao hàm lực lượng thần tính. Là nguyên liệu để hầm thành lò bảo dược; ăn vào giúp đột phá cảnh giới.","nguon":["@c0123"]},{"id":"trung-than-mau-vang","name":"Trứng thần màu vàng","category":"nguyen-lieu","categoryLabel":"Trứng thần linh","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Trứng to như chậu nước, như đúc bằng vàng ròng, vỏ có hoa văn kỳ dị lưu động ánh sáng, cuối cùng nở ra một thần linh non.","detail":"Quả trứng nhóc tỳ cướp được, to như chậu nước, tỏa sóng năng lượng thần bí, nghi là hậu duệ Thần linh. Vỏ cứng nhưng bị đục bằng đá nhọn; dưới tác động lửa và Bảo Thuật khi nhóc tỳ dùng nó làm lá chắn, vỏ trứng vỡ vụn, một sinh vật nhỏ cuộn tròn trong lòng bàn tay nhóc tỳ — thực sự ấp ra một thần linh non.","nguon":["@c0124"]},{"id":"trai-tim-hung-thu-huyet-nhuc-bao-duoc","name":"Trái tim hung thú (huyết nhục bảo dược)","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bảo dược","soHuu":["Hỏa Linh Nhi"],"trangThai":"da-dung","blurb":"Trái tim hung thú đựng trong đỉnh ngọc, tinh hoa thần tính của hung vật cực mạnh.","detail":"Nơi ngưng kết tinh hoa thần tính của hung vật cực mạnh, đựng trong đỉnh ngọc; Hỏa Linh Nhi lấy ra cho sói con Ấu Thần ăn sạch.","nguon":["@c0125"]},{"id":"chuoi-niem-chau-vang-su-tu","name":"Chuỗi niệm châu vàng (cốt châu Sư Tử)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Sư Tử chín đầu"],"trangThai":"dang-co","blurb":"Cốt châu Hoàng kim do Cửu Linh Vương ban cho Sư Tử chín đầu, mỗi hạt như một thế giới nhỏ, mang quy tắc Phù Văn của dòng tộc.","detail":"Chuỗi niệm châu chế từ Hoàng kim di cốt của tiền bối bộ tộc Sư Tử chín đầu, mỗi hạt như một thế giới nhỏ chứa quy tắc Phù Văn dòng tộc; do Cửu Linh Vương ban cho. Khi phá trận, Sư Tử phun ra để đánh tan thạch lâm.","nguon":["@c0126"]},{"id":"cửu-chuyen-linh-dan","name":"Cửu Chuyển Linh Đan","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Đan cần sáu giọt bảo huyết Thái Cổ di chủng mạnh nhất để luyện chế.","detail":"Linh đan cao cấp cần sáu giọt bảo huyết Thái Cổ di chủng mạnh nhất để luyện; là lý do nhiều thế lực Nhân tộc muốn bắt Sư Tử chín đầu để lấy bảo huyết.","nguon":["@c0126"]},{"id":"bao-tan-vu-tu-mach","name":"Bảo Tán (dù)","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"","soHuu":["Vũ Tử Mạch"],"trangThai":"hong","blurb":"Cây dù lớn (Bảo Cụ) của Vũ Tử Mạch dùng che lôi điện, bị Cốt Tiễn cắt đứt rách nát.","detail":"Vũ Tử Mạch lấy cây dù lớn (Bảo Cụ) che lôi điện của nhóc tỳ, nhưng bị Cốt Tiễn vàng cắt đứt, trong nháy mắt rách rưới hoàn toàn.","nguon":["@c0128"]},{"id":"bao-y-long-chim-tim","name":"Bảo Y lông chim màu tím","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"","soHuu":["Vũ Tử Mạch"],"trangThai":"hong","blurb":"Áo giáp Bảo Cụ bện từ lông chim màu tím của Vũ Tử Mạch, bị bảo kính Toan Nghê đánh nổ tung hóa tro bụi.","detail":"Vũ Tử Mạch triển khai Bảo Y bện từ lông chim màu tím, lấp lánh như ánh bình minh để phòng ngự, nhưng cuối cùng bị bảo kính Toan Nghê đánh nổ tung, áo giáp hóa tro bụi, thân thể lộ ra.","nguon":["@c0128"]},{"id":"quyen-sach-co-nhieu-mau-vu-tu-mach","name":"Quyển sách cổ nhiều màu","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vũ Tử Mạch"],"trangThai":"hong","blurb":"Quyển sách cổ Phù Văn của Vũ Tử Mạch dùng thi triển Bảo Thuật Thông Linh, bị cối xay bạc phá vỡ.","detail":"Quyển sách cổ nhiều màu chứa Phù Văn của Vũ Tử Mạch, như gánh chịu lực lượng năm tháng nên gần như bất hủ. Khi chủ nhân giận dữ thì lúc sáng lúc tối, trông rất bất ổn; cuối cùng bị cối xay bạc của nhóc tỳ nổ tung phá vỡ, khiến Bảo Thuật Thông Linh mất hiệu lực.","nguon":["@c0128"]},{"id":"ho-lo-mau-xanh-te-linh","name":"Hồ lô màu xanh (Tế Linh)","category":"khac","categoryLabel":"Vật phẩm thần bí","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Trái hồ lô màu xanh nằm dưới lá khô của giàn dây hồ lô Tế Linh, mang Phù Văn cổ và khí Hỗn Độn bao phủ.","detail":"Nằm dưới đám lá khô của giàn dây hồ lô Tế Linh trong khu vườn cổ, kích thước tương đương trái hồ lô vàng óng của vị lão tiền bối Bổ Thiên các. Trên hồ lô có Phù Văn cổ lấp loé, khí Hỗn Độn lượn lờ bao phủ như một thế giới mơ hồ trấn áp lại. Cả nhóc tỳ lẫn Bóng Lông đều muốn hái nhưng bản năng ngăn cản.","nguon":["@c0110"],"aliases":["Hồ lô vỏ xanh (Tế Linh)"]},{"id":"ho-lo-vo-xanh-te-linh","name":"Hồ lô vỏ xanh","aliases":["Trái hồ lô màu xanh"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tế Linh"],"trangThai":"dang-co","blurb":"Trái hồ lô vỏ xanh trên giàn dây hồ lô khô vàng của Tế Linh; khi bị tiếp cận phát khí Hỗn Độn hiển hóa Phù Văn đẩy lui.","detail":"Nằm trên giàn dây hồ lô khô vàng ở Thượng Cổ Tịnh Thổ. Khi Thạch Hạo định chạm vào để đánh thức Tế Linh, hồ lô phát ra khí Hỗn Độn, đạo âm chấn động, hiển hóa Phù Văn ngàn tia vạn sợi, khí thế như thời chưa khai thiên lập địa, đẩy lui nó.","nguon":["@c0111"]},{"id":"ho-lo-mau-xanh-khai-thong-dao","name":"Hồ lô màu xanh (khai thông đạo)","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":[],"trangThai":"dang-co","blurb":"Hồ lô màu xanh hiện lên trong hào quang, lắc lư không ngừng, dựng thành một con đường màu xanh làm thông đạo.","detail":"Trong một tiếng “Ầm”, nơi ở của Tế Linh xuất hiện mảnh hào quang; một cái hồ lô màu xanh hiện lên lắc lư không ngừng, dựng thành con đường màu xanh để đoàn người đi vào thông đạo và toàn bộ biến mất khỏi Bổ Thiên các.","nguon":["@c0114"]},{"id":"manh-xuong-thai-co-di-chung","name":"Mảnh xương Thái cổ di chủng","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":[],"trangThai":"dang-co","blurb":"Những mảnh xương của Thái cổ di chủng được các trưởng lão thu lại tại nơi ở của Tế Linh.","detail":"Đoàn người tiến vào nơi ở của Tế Linh, các trưởng lão yên lặng cầu khẩn rồi thu lại những mảnh xương của Thái cổ di chủng gần giàn dây hồ lô.","nguon":["@c0114"]},{"id":"tang-than-vat-theo-nguoi","name":"Tang thần","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Thứ mang bên người nhóc tỳ khiến nó buộc phải nghe theo, nếu không đi sẽ mất mạng.","detail":"Vật/thứ theo bên người Thạch Hạo, gắn với thế lực bí ẩn “Hắn”; Đào Dã dọa nếu không vào Bách Đoạn sơn thì “Hắn” không đáp ứng, nó sớm muộn mất mạng. Danh tính và công năng đầy đủ chưa rõ.","nguon":["@c0113"]},{"id":"khay-bac-than-nguyet","name":"Khay bạc","aliases":["Khay bạc như Thần Nguyệt"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Khay bạc thánh khiết nhóc tỳ triệu ra sau lưng để chắn nham thạch và lửa.","detail":"Ánh bạc như nước hóa thành khay bạc cao gần bằng người hiện ra sau lưng nhóc tỳ, thánh khiết như Thần Nguyệt; bất luận nham thạch nóng chảy hay lửa cháy đều bị nó ngăn lại khi Hỏa Vân Tước trút mưa Hỏa văn.","nguon":["@c0118"]},{"id":"huyet-nhuc-bao-duoc-hoa-van-tuoc","name":"Huyết nhục bảo dược (thịt Hỏa Vân Tước)","aliases":[],"category":"dan-duoc","categoryLabel":"Bảo dược","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Hơn hai mươi cân thịt Hỏa Vân Tước, ăn vào tăng tinh khí, giúp tiến tới đột phá.","detail":"Thịt tươi thơm sáng óng ánh nhóc tỳ chém rụng được từ Hỏa Vân Tước; nấu chín ăn vào thân thể phát tia sáng, sức mạnh tinh thuần lan khắp thân, tăng tinh khí. Nhóc tỳ tin nếu ngày nào cũng ăn loại huyết nhục bảo dược này chẳng bao lâu sẽ đột phá.","nguon":["@c0118"]},{"id":"tui-da-dung-trung-vang","name":"Túi bằng da thú (đựng trứng vàng)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Người đội nón lá"],"trangThai":"Bị phá nát","blurb":"Túi da thú người đội nón lá dùng đựng quả trứng vàng nghi hậu duệ Lang Thần, phát ra ánh sáng.","detail":"Túi làm bằng da thú, được người đội nón lá mang theo để đựng quả trứng vàng to bằng chậu nước. Túi phát ra ánh sáng khi chứa trứng. Khi người đội nón lá bị thương trong lúc tranh cướp, túi da vỡ ra khiến quả trứng vàng rơi xuống, dẫn tới màn tranh đoạt và việc nhóc tỳ ôm trứng bỏ chạy.","nguon":["@c0123"]},{"id":"quat-bac-rach-nat","name":"Quạt bạc rách nát","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo Cụ (phù cốt nguyên thủy)","soHuu":["Thạch Hạo"],"trangThai":"hong","blurb":"Cây quạt phù cốt nguyên thủy ngân quang lấy từ cường giả Linh Tộc, được tinh khí và sấm chớp nuôi dưỡng.","detail":"Cây quạt rách nát ngân quang mà Thạch Hạo lấy từ cường giả Linh Tộc, từng bị Cốt Tiễn màu vàng cắt nát. Khi bị bốn đại cường giả Vũ tộc vây, Thạch Hạo vận bảo kính Toan Nghê truyền lực sấm sét vào khiến quạt thức tỉnh rồi ném ra nổ tung đánh về bốn người, phế bỏ luôn cây quạt.","nguon":["@c0130"]},{"id":"hac-sat-lien-thanh-duoc","name":"Hắc Sát Liên (Thánh Dược)","cn":"","category":"dan-duoc","categoryLabel":"Linh dược / Thánh Dược","phamCap":"Thánh Dược","soHuu":["Bổ Thiên Các"],"trangThai":"Đã bị đào cả gốc lẫn ngọn, chỉ còn cái hố","blurb":"Cây thuốc quý bậc Thánh Dược của Bổ Thiên Các, sinh trưởng 800 năm, sắp lột xác khi tròn 1000 tuổi.","detail":"Hắc Sát Liên là Thánh Dược trục sự kiện của Bổ Thiên Các, đã sinh trưởng 800 năm và sắp lột xác khi tròn 1000 tuổi. Là loại Thánh Dược cực hiếm ở Đại Hoang — vật có thể làm người chết sống lại — nên khiến các tiền bối những thế lực khiếp sợ khi biết Bổ Thiên Các gây trồng được. Cây thuốc được canh giữ bởi Hắc Hổ Sát trong một hố đất. Khi Trác Vân trưởng lão dẫn đoàn tới giới thiệu thì phát hiện Hắc Sát Liên đã bị kẻ khác đào cả gốc lẫn ngọn, chỉ còn trơ lại cái hố, khiến ông từ ung dung chuyển sang nổi điên gào giận.","nguon":["@c0104"]},{"id":"cot-tien-vang-kim-te-linh","name":"Cốt Tiễn vàng kim","cn":"","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ","soHuu":["Nhóc tỳ"],"trangThai":"Nhóc tỳ đoạt từ tay Tế Linh Xuyên Sơn Giáp, đang sử dụng","blurb":"Bảo Cụ kim cốt kinh người, phát dị tượng núi thây biển máu, từng gây hạo kiếp đồ sát vô số bộ lạc.","detail":"Cốt Tiễn màu vàng kim, một Bảo Cụ có uy lực vượt xa tưởng tượng: khi thi triển phát ra dị tượng núi thây biển máu, tương truyền từng gây hạo kiếp đồ sát vô số bộ lạc. Nhóc tỳ đoạt được từ tay Tế Linh Xuyên Sơn Giáp vàng kim, nghi là bảo vật do tổ tiên truyền lại. Trong trận tranh đoạt Ấu Thần, Cốt Tiễn vọt tới không những đánh gãy hung đao (cốt đao) của Vũ Vương mà còn chặt đứt một cánh tay của Vũ Vương, máu phun tung tóe, khiến đám truy đuổi biến sắc rút lui.","nguon":["@c0125"]},{"id":"dinh-ngoc-trai-tim-hung-thu","name":"Đỉnh ngọc chứa trái tim hung thú","cn":"","category":"dan-duoc","categoryLabel":"Huyết nhục bảo dược","phamCap":"Huyết nhục bảo dược","soHuu":["Hỏa Linh Nhi"],"trangThai":"Hỏa Linh Nhi lấy ra cho sói con (Ấu Thần) ăn","blurb":"Trái tim của một hung vật cực mạnh ngưng kết tinh hoa thần tính, đựng trong đỉnh ngọc, là huyết nhục bảo dược.","detail":"Một chiếc đỉnh ngọc chứa trái tim hung thú — trái tim của một hung vật cực mạnh, ngưng kết tinh hoa thần tính, được xem là huyết nhục bảo dược quý giá. Hỏa Linh Nhi lấy từ trong túi ra, cùng hai cây Linh dược, đưa cho sói con (Ấu Thần) ăn để nuôi dưỡng nó trưởng thành. Sói con ăn sạch.","nguon":["@c0125"]},{"id":"bat-lao-than-tuyen-di-bao","name":"Bất Lão Thần Tuyền","cn":"","category":"khac","categoryLabel":"Thần tuyền / dị bảo","phamCap":"Dị bảo","soHuu":[],"trangThai":"Mục tiêu tìm kiếm; nhóc tỳ ép Sư Tử chín đầu giúp tìm","blurb":"Thần tuyền dị bảo được cho là có thể trị lành thương tổn, kể cả mấy cái đầu bị mất của Sư Tử chín đầu.","detail":"Bất Lão Thần Tuyền là một dị bảo dạng thần tuyền mà nhóc tỳ đòi tìm trong Tiểu Thế Giới. Nhóc tỳ nói nếu tìm được thì có thể trị tốt được cho mấy cái đầu bị mất của Sư Tử chín đầu, nên ép sư tử chở đi tìm và phát thệ hỗ trợ. Gắn với cơ duyên chữa lành trong Tiểu Thế Giới.","nguon":["@c0125"]},{"id":"te-linh-tang-da-ky-la","name":"Tế Linh (tảng đá kỳ lạ)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":[],"trangThai":"Được mang tới sơn môn Bổ Thiên các làm bằng chứng truy nã","blurb":"Tảng đá được nghi là Tế Linh, mang tới trên da thú cổ, hai mặt hiện chữ khiêu khích do Nhóc siêu quậy để lại.","detail":"Một tảng đá kỳ lạ được nghi là Tế Linh, được da thú cổ lấp lánh phù văn chở tới sơn môn Bổ Thiên các cùng cường giả. Mặt trước tảng đá hiện chữ 「Anh Minh Thần Vũ, Quang Minh Chính Đại」, mặt sau hiện 「Nắm Búa Nơi Tay, Ta Có Thiên Hạ」 — dấu vết do Nhóc siêu quậy để lại. Khi được đưa lên cho ba ngàn tân đệ tử xem, dòng chữ khiến mọi người kinh hô nhận ra tên nhóc siêu quậy khét tiếng, trở thành bằng chứng để Hùng Phi trưởng lão phát lệnh truy nã.","nguon":["@c0106"]},{"id":"van-tu-hoan-cot","name":"Văn tự Hoàn Cốt","cn":"","category":"khac","categoryLabel":"Văn tự nhập môn","phamCap":"","soHuu":[],"trangThai":"Được hai trưởng lão giảng cho tân đệ tử Bổ Thiên các","blurb":"Loại văn tự nhập môn mà hai vị trưởng lão giảng giải cho tân đệ tử rồi vội rời đi.","detail":"Văn tự Hoàn Cốt là thứ Hùng Phi và Trác Vân giảng giải cho trăm tân đệ tử tại khu núi đá của Bổ Thiên các. Trong mấy ngày liền, hai vị trưởng lão chỉ gặp mặt một lần, giảng giải văn tự Hoàn Cốt rồi vội vã rời đi, không ở lại lâu.","nguon":["@c0106"]},{"id":"cot-tien-mau-vang-vu-tu-mach","name":"Cốt Tiễn màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"Đang dùng","blurb":"Mũi tên cốt màu vàng uy lực mạnh của nhóc tỳ, cắt đứt cây Bảo Tán và hủy một Bảo Cụ của chính nhóc tỳ.","detail":"Cốt Tiễn màu vàng là pháp bảo dạng mũi tên do nhóc tỳ bắn ra trong trận chiến với Vũ Tử Mạch. Uy lực mạnh mẽ: nó cắt đứt cây Bảo Tán (dù) của Vũ Tử Mạch trong nháy mắt khiến cây dù rách rưới, đồng thời cùng tia chớp vàng đánh vào người nàng khiến nàng ho ra máu. Trong quá trình giao chiến, Cốt Tiễn cũng hủy một Bảo Cụ của chính nhóc tỳ, khiến nó đau lòng.","nguon":["@c0128"]},{"id":"bao-tan-du-vu-tu-mach","name":"Bảo Tán (dù)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo Cụ","soHuu":["Vũ Tử Mạch"],"trangThai":"Bị hủy","blurb":"Cây dù lớn (Bảo Cụ) của Vũ Tử Mạch dùng che lôi điện, bị Cốt Tiễn cắt đứt rách nát.","detail":"Bảo Tán là một Bảo Cụ hình dù/ô lớn của Vũ Tử Mạch, được nàng lấy ra để che chắn lôi điện của nhóc tỳ. Tuy nhiên nó bị Cốt Tiễn màu vàng của nhóc tỳ cắt đứt, trong nháy mắt rách rách rưới rưới, hư hại hoàn toàn.","nguon":["@c0128"]},{"id":"chin-rang-nanh-vang-su-tu","name":"Chín răng nanh màu vàng","cn":"","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ","soHuu":["Sư Tử chín đầu"],"trangThai":"Đang sử dụng","blurb":"Sư Tử chín đầu phun ra chín răng nanh màu vàng để tấn công cường giả phía Tây.","detail":"Bảo cụ vũ khí của Sư Tử chín đầu (Hoàng Kim sư tử). Trong lúc bị bốn Người phong ấn Vũ tộc vây bắt, Sư Tử chín đầu phun ra chín răng nanh màu vàng đánh về phía cường giả trấn giữ phương Tây, dùng làm đòn công kích trong cuộc huyết chiến bỏ chạy.","nguon":["@c0129"]},{"id":"buc-tranh-nhan-dien-nhoc-ty","name":"Bức tranh (nhận diện nhóc tỳ)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Sinh vật hình người ánh bạc"],"trangThai":"Do kẻ ánh bạc nắm giữ","blurb":"Bức tranh kẻ ánh bạc dùng để đối chiếu, nhận diện đúng nhóc tỳ là mục tiêu cần truy tìm.","detail":"Một bức tranh mà sinh vật hình người ánh bạc mang theo, dùng để đối chiếu nhận diện nhóc tỳ. Sau khi xem tranh, hắn xác nhận nhắm đúng mục tiêu rồi mới ra tay chiêu dụ. Việc dùng tranh truy tìm gợi mở nhóc tỳ là đối tượng bị nhiều thế lực (Hoàng Kim sư tử chín đầu, kẻ ánh bạc) tranh đoạt.","nguon":["@c0118"]},{"id":"chi-ton-cot","name":"Chí Tôn Cốt","cn":"","category":"khac","categoryLabel":"Bảo vật (cốt)","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"Đã mất","blurb":"Bảo vật nhóc tỳ từng sở hữu nhưng đã mất; dẫu mất nó vẫn quật khởi được, chứng minh thiên tư đáng sợ.","detail":"Chí Tôn Cốt là bảo vật mà nhóc tỳ (con Thạch Tử Lăng) từng sở hữu rồi bị mất. Trong mắt bốn cường giả Vũ tộc, việc nhóc tỳ đánh mất Chí Tôn Cốt mà vẫn có thể quật khởi chính là bằng chứng cho thiên tư kinh khủng của nó — đúng nỗi lo của một nguyên lão trong tộc, khiến bọn Thạch Nghị quyết diệt trừ nhân tố bất định này.","nguon":["@c0130"]},{"id":"thai-nhat-chan-thuy","name":"Thái Nhất Chân Thủy","aliases":["Thái Nhất Thần Thủy","Thái Nhất Chân thủy","thủy bảo"],"category":"khac","categoryLabel":"Thần dịch","phamCap":"Thần dịch trân quý","soHuu":[],"trangThai":"dang-co","blurb":"Thần dịch cực kỳ trân quý, một giọt có giá trị liên thành, ẩn chứa Thủy chi pháp tắc; mục tiêu tranh đoạt của Vũ tộc.","detail":"Loại thần dịch có nhiều công hiệu: luyện thành tuyệt thế bảo đan, thêm một giọt tăng phẩm chất Bảo Cụ một đoạn lớn, ẩn chứa Thủy chi pháp tắc, hỗ trợ tu hành làm chơi ăn thật. Chư Thần khi luyện bảo cũng dùng nó để tẩm bổ linh tính cho Bảo Cụ; một giọt giá trị liên thành, trân quý không cách nào tưởng tượng. Vũ tộc cảm ứng khí tức từ mấy trăm năm trước, ra quân ồ ạt và tìm được một ao thần dịch trong sa mạc; hồ này xuất hiện ảo cảnh vừa lừa dối vừa kêu gọi người tiến gần. Với Vũ tộc, thủy bảo có thể khiến tộc quật khởi và xuất hiện một vị Nhân Hoàng.","nguon":["@c0131","@c0200"]},{"id":"trung-toa-son-dieu","name":"Trứng Tọa Sơn Điêu","aliases":[],"category":"dan-duoc","categoryLabel":"Đại bổ dược","phamCap":"Thánh Phẩm","soHuu":["Thạch Hạo","Đại Hồng Điểu"],"trangThai":"da-dung","blurb":"Đại bổ dược Thánh Phẩm, ba quả trứng to như cối đá, vỏ đen óng như Mặc Ngọc, giàu tinh khí thần.","detail":"Ba quả trứng lớn của Tọa Sơn Điêu, vỏ đen óng như Mặc Ngọc, bên trong ẩn tinh khí nội hàm Phù Văn, giàu tinh khí thần, dùng chữa thương và tẩm bổ. Đại Hồng Điểu cắt trứng bằng lông vũ, phun lửa nướng chín; Thạch Hạo ăn cả ba quả (nặng hơn cả trọng lượng cơ thể) để luyện hóa chữa lành toàn bộ vết thương, Đại Hồng Điểu chỉ ăn được một quả.","nguon":["@c0131"]},{"id":"ngan-lu-thao","name":"Ngân Lũ Thảo","aliases":[],"category":"nguyen-lieu","categoryLabel":"Linh thảo","phamCap":"Chưa rõ","soHuu":[],"trangThai":"dang-co","blurb":"Loại linh thảo mềm mại ấm áp được Tọa Sơn Điêu lót trong tổ chim.","detail":"Loại thảo mềm mại ấm áp mà Tọa Sơn Điêu lót trong tổ chim khổng lồ để ấp trứng.","nguon":["@c0131"]},{"id":"long-than-tieu-hong-dieu","name":"Lông thần Tiểu Hồng Điểu","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chí Tôn (thần uy)","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Cái lông chim đỏ tươi như máu đựng trong hộp đá, tỏa xích hà và thần uy Chí Tôn.","detail":"Lông chim đỏ tươi như máu, tỏa xích hà và hỏa quang đặc biệt, mang thần uy Chí Tôn khiến Đại Hồng Điểu (cũng là loài chim) run sợ khuất phục, lật mặt quỳ xin làm đồ đệ.","nguon":["@c0132"]},{"id":"sa-mac-ngan","name":"Sa Mạc Ngân","category":"dan-duoc","categoryLabel":"Bảo dược","phamCap":"Bảo dược truyền thuyết","soHuu":["Tiêu Thiên"],"trangThai":"da-dung","blurb":"Bảo dược trong truyền thuyết hơn xa linh dược bình thường, là đóa hoa trắng bạc trên cây xương rồng.","detail":"Đóa hoa trắng bạc đong đưa trên cây xương rồng giữa sa mạc, hương thơm nức, ánh bạc rơi vãi như mưa ánh sáng; do bò cạp bạc khổng lồ canh giữ. Tiêu Thiên hái được và luyện hóa để đột phá Động Thiên thứ tám.","nguon":["@c0132"]},{"id":"hop-da","name":"Hộp đá","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Hộp đá Thạch Hạo dùng để cất giữ lông thần Tiểu Hồng Điểu.","detail":"Hộp đá chứa cái lông thần đỏ tươi của Tiểu Hồng Điểu, Thạch Hạo mở ra để tỏa thần uy khuất phục Đại Hồng Điểu.","nguon":["@c0132"]},{"id":"nuoc-hoang-tuyen","name":"Nước Hoàng Tuyền","category":"khac","categoryLabel":"Bảo dịch","phamCap":"Không rõ","soHuu":["Vũ Văn Thành","Vũ Côn"],"trangThai":"dang-co","blurb":"Bảo dịch trong bảo bình của Vũ tộc, luyện từ phù cốt, phù văn và nước Âm Hà; tỏa ô quang đen phá hủy hài cốt phù văn.","detail":"Ba người Vũ tộc mở bảo bình nước Hoàng Tuyền, tế bảo thuật biến ô quang màu đen thành sinh linh (quỷ quái, Li Long, hình người) phá vỡ toàn bộ hài cốt do Thái Nhất Chân Thủy triệu hoán. Luyện từ phù cốt, phù văn, nước Âm Hà lấy từ mộ phần; vốn định dùng để thâm nhập Tử Vong cấm địa nên không muốn tiêu hao hết.","nguon":["@c0133"]},{"id":"tui-can-khon-phong-che","name":"Túi càn khôn phỏng chế","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Phỏng chế","soHuu":["Vũ Côn"],"trangThai":"hong","blurb":"Bảo cụ thu nạp Vũ Côn tế ra từ tấm da thú, phù văn vô tận; là hàng phỏng chế của túi càn khôn chính phẩm Thượng Cổ.","detail":"Vũ Côn tế ra túi càn khôn phỏng chế từ tấm da thú để thu linh đằng thủ hộ, nhưng túi bị đâm vỡ tan. Tiêu Thiên giải thích túi càn khôn Thượng Cổ chính phẩm luyện từ da Thái Cổ hung thú thiên giai, không gì không thể thu vào; đồ này chỉ là hàng phỏng chế.","nguon":["@c0133"]},{"id":"di-vat-vu-than","name":"Di vật Vũ thần","category":"khac","categoryLabel":"Chứng vật","phamCap":"Không rõ","soHuu":["Vũ Văn Thành"],"trangThai":"dang-co","blurb":"Di vật của Vũ thần (nghiên mực đã dùng hết, chặn giấy) có hào quang thần thánh nhưng không phù văn, dùng chứng minh Vũ tộc là hậu duệ Vũ thần.","detail":"Vũ tộc dùng di vật Vũ thần — nghiên mực đã dùng hết, chặn giấy... tỏa hào quang thần thánh, không có phù văn — để chứng thực là hậu duệ Vũ thần, khiến Thái Nhất Chân Thủy nguyện đi theo Vũ tộc để có cơ hội phong thần.","nguon":["@c0133"]},{"id":"dinh-ngoc-vu-toc","name":"Đỉnh ngọc Vũ tộc","aliases":["Bảo Cụ đỉnh ngọc"],"category":"phap-bao","categoryLabel":"Bảo cụ chứa đựng","phamCap":"Không rõ","soHuu":["Vũ Văn Thành"],"trangThai":"dang-co","blurb":"Đỉnh ngọc Vũ tộc dùng để thu chứa Thái Nhất Chân Thủy; bên trong có nước, bị Nhóc Tỳ nhào vào nuốt sạch.","detail":"Vũ tộc mời Thái Nhất Chân Thủy hóa ánh sáng tiến vào đỉnh ngọc, một giọt không thiếu, mơ tưởng lập quốc; nhưng Nhóc Tỳ nhào vào Bảo Cụ đỉnh ngọc quẫy nước rầm rầm và nuốt từng ngụm lớn Thái Nhất Chân Thủy.","nguon":["@c0133"]},{"id":"quy-thuan-mai-rua","name":"Quy thuẫn mai rùa","category":"phap-bao","categoryLabel":"Khiên / Bảo cụ","phamCap":"Không rõ","soHuu":["Tiêu Thiên"],"trangThai":"hong","blurb":"Tấm khiên Tiêu Thiên tế ra là mai rùa tỏa sáng xanh biếc lóe vô số phú văn áo nghĩa; làm bàn đạp cho Nhóc Tỳ rồi vỡ vụn.","detail":"Tiêu Thiên xuất ra quy thuẫn — mai rùa xanh biếc lóe phú văn áo nghĩa — làm bàn đạp cho Nhóc Tỳ bật xông vào đỉnh ngọc. Do sức bật kinh khủng của Nhóc Tỳ, quy thuẫn rạn nứt rồi vỡ vụn hoàn toàn, đẩy Tiêu Thiên văng ra năm sáu dặm.","nguon":["@c0133"]},{"id":"dinh-quang-chau","name":"Định Quang Châu","cn":"","category":"phap-bao","categoryLabel":"Dị bảo","phamCap":"Không rõ","soHuu":["Tiêu Thiên","Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Mảnh vỡ của Định Quang Châu thời thượng cổ đánh bóng mà thành, tạo màn sáng hình cầu trói chặt và ngăn phù văn.","detail":"Dị bảo do Tiêu Thiên mang tới, vốn là mảnh vỡ của Định Quang Châu thời thượng cổ. Nhóc Tỳ quát “Định!” lấy ra tạo màn sáng hình cầu ngăn công kích phù văn của Vũ tộc và tạm giữ Thái Nhất Chân Thủy. Do đã hư hại nên chỉ phát huy một phần uy lực, màn sáng mờ dần rồi sắp hết tác dụng; cuối cùng được bỏ vào bình ngọc cùng nước thần.","nguon":["@c0134"]},{"id":"binh-ngoc-nuoc-than","name":"Bình ngọc","cn":"","category":"khac","categoryLabel":"Vật chứa","phamCap":"Không rõ","soHuu":["Tiêu Thiên"],"trangThai":"dang-co","blurb":"Bình ngọc Nhóc Tỳ đổ đầy Thái Nhất Chân Thủy và bỏ Định Quang Châu vào, cuối cùng Tiêu Thiên ôm giữ.","detail":"Nhóc Tỳ vội đổ đầy nước thần vào bình ngọc rồi bỏ Định Quang Châu vào trong; sau khi chạy thoát, Tiêu Thiên ôm giữ bình ngọc, kích động vì đã lấy được phần nước thần.","nguon":["@c0134"]},{"id":"noi-den-dai-hong-dieu","name":"Nồi đen của Đại Hồng Điểu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại Hồng Điểu"],"trangThai":"dang-co","blurb":"Nồi đen thực chất là một quả trứng chim mài giũa thành, dùng để hấp thu và phong ấn Thái Nhất Chân Thủy.","detail":"Màu đen bóng như mặc ngọc, phù văn chằng chịt, lôi điện tia lửa phong tỏa. Đại Hồng Điểu phun ra để hấp thu, trấn áp và phong ấn Thái Nhất Chân Thủy vào trong.","nguon":["@c0135","@c0164"]},{"id":"bao-kinh-toan-nghe","name":"Bảo kính Toan Nghê","aliases":["bảo cốt Toan Nghê"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Chí bảo","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Chí bảo lấy từ trên người Thái Cổ di chủng, tỏa tia sấm sét dương cương màu vàng thô to, hơn xa bảo cụ thông thường.","detail":"Thạch Hạo dùng bảo kính Toan Nghê áp chế và phá nứt sừng thú đen tà khí của Vũ Văn Thiên.","nguon":["@c0137"]},{"id":"sung-thu-den","name":"Sừng thú đen","aliases":["bảo cụ tà khí"],"category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Vũ Văn Thiên"],"trangThai":"hong","blurb":"Bảo cụ tà khí Vũ Văn Thiên phun ra, phát thần âm điếc tai như muốn đoạn hồn phách.","detail":"Bị bảo kính Toan Nghê phá nứt rồi Cốt Tiễn màu vàng cắt đứt đôi rơi xuống đất.","nguon":["@c0137"]},{"id":"linh-vu-vu-van-thien","name":"Linh Vũ","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Vũ Văn Thiên"],"trangThai":"hong","blurb":"Chiếc lông đuôi chim màu tím Vũ Văn Thiên ngồi lên để bay lên trời.","detail":"Vũ Văn Thiên ngồi trên Linh Vũ định bay vút lên thì bị Cốt Tiễn màu vàng kẹp đứt đôi, suýt mất mạng.","nguon":["@c0137"]},{"id":"tam-da-giao-thu","name":"Tấm da giao thú","aliases":["phù cốt nguyên thủy"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ hiếm","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Tấm da thú của con giao, dung hợp vào thân người thành vuốt giao phá núi vỡ đá. Nhóc Tỳ đoạt được từ thiếu niên cầm đầu Võ Vương phủ.","detail":"Bảo cụ rất hiếm, chỉ người thân phận không bình thường mới có; khi hợp vào thân hóa thành vuốt giao thô to chi chít vảy, phá núi vỡ đá. Thiếu niên cầm đầu Võ Vương phủ dùng nó tấn công Nhóc Tỳ nhưng bị đoạt mất.","nguon":["@c0138"]},{"id":"bao-phien-nam-mau","name":"Bảo Phiến năm màu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chim Loan năm màu"],"trangThai":"dang-co","blurb":"Bảo phiến năm màu chim Loan phun ra, tạo thành từ cánh chim, đánh xuống tạo hố lớn.","detail":"Chim Loan năm màu phun ra Bảo Phiến năm màu tạo thành từ cánh chim; khi đánh xuống tạo thành hố lớn. Là pháp bảo phòng-công của hậu duệ Thần điểu trong trận chiến với Nhóc Tỳ.","nguon":["@c0140"]},{"id":"phi-kiem-rang-nanh-do-tham","name":"Phi kiếm răng nanh đỏ thẫm","cn":"","aliases":["Phi kiếm mày đỏ thẫm","phi kiếm đỏ thẫm","phù cốt của Phì Di","Phi kiếm răng nanh"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"bi-cuop","blurb":"Phù cốt mạnh nhất của Phì Di, tế luyện mấy năm chuyển hóa thành phi kiếm; dài bằng lòng bàn tay, tạo từ răng nanh đánh bóng như mã não đỏ, linh tính mạnh phát ánh lửa đốt cháy.","detail":"Phi kiếm răng nanh đỏ thẫm được Phì Di phun từ miệng, dài bằng lòng bàn tay, tạo từ răng nanh đánh bóng như mã não đỏ, linh tính mạnh và phát ánh lửa đốt cháy. Là phù cốt mạnh nhất của Phì Di, tế luyện mấy năm chuyển hóa thành phi kiếm; bị Nhóc Tỳ nhắm đoạt (cố ý không dùng Cốt Tiễn để giữ nguyên bảo cụ), rơi vào tay Nhóc Tỳ.","nguon":["@c0140"]},{"id":"giao-long-tien","name":"Long Giao tiễn","cn":"","aliases":["Giao Long tiễn"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Tiễn pháp bảo của Nhóc Tỳ, vệt ánh sáng suýt cắt đôi đối thủ khiến máu chảy đầm đìa.","detail":"Nhóc Tỳ phát động Long Giao tiễn, vệt ánh sáng suýt cắt đôi Phì Di khiến máu chảy đầm đìa, mở đường cho đòn bảo kính sấm sét đánh gục đối thủ.","nguon":["@c0140","@c0198"]},{"id":"suc-dia-phu","name":"Súc Địa phù","cn":"","category":"phap-bao","categoryLabel":"Thần phù","phamCap":"Thần phù thời Thượng Cổ","soHuu":["Người mặc áo bào xanh"],"trangThai":"Số lần dùng có hạn","blurb":"Thần phù thời Thượng Cổ, dán dưới lòng bàn chân hóa thành lưu quang di chuyển tức thời.","detail":"Súc Địa phù là sản phẩm thời Thượng Cổ, giá trị liên thành. Khi dán dưới lòng bàn chân, người dùng hóa thành lưu quang di chuyển tức thời trong nháy mắt, thoát khỏi vòng vây. Người mặc áo bào xanh dùng nó để trốn thoát sau khi bị Nhóc Tỳ cùng đoàn Thái Cổ di chủng đánh trọng thương trong phế tích Bách Đoạn sơn. Nhược điểm là số lần sử dụng có hạn, dùng hết thì không còn tác dụng.","nguon":["@c0142"]},{"id":"cot-kiem-ao-bao-xanh","name":"Cốt kiếm áo bào xanh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Người mặc áo bào xanh"],"trangThai":"Rạn nứt","blurb":"Bảo cốt óng ánh của Người phong ấn, ánh kiếm như ngân hà cắt đôi tảng đá mười mấy vạn cân.","detail":"Cốt kiếm là bảo cốt óng ánh, ánh kiếm rực rỡ tựa ngân hà, uy lực cực lớn — một nhát chém đôi tảng đá nặng mười mấy vạn cân. Người mặc áo bào xanh dùng nó chém lén Nhóc Tỳ. Khi bị Nhóc Tỳ và đoàn Thái Cổ di chủng quần công, cốt kiếm bị rạn nứt.","nguon":["@c0142"]},{"id":"cot-thap-trang-toat","name":"Cốt tháp trắng toát","cn":"","category":"than-khi","categoryLabel":"Dị bảo","phamCap":"Cốt tháp thần thánh","soHuu":[],"trangThai":"Chưa thu phục — bị tranh đoạt","blurb":"Tháp xương trắng toát lơ lửng trong sơn cốc, hào quang lượn lờ, khí lành mù mịt, tỏa hàng vạn tia Thánh quang.","detail":"Cốt tháp trắng toát là dị bảo thần thánh lơ lửng trong sơn cốc giữa phế tích Thái Cổ, hào quang lượn lờ, khí lành mù mịt. Khi bị Nhóc Tỳ dùng bảo kính Toan Nghê chiếu tới rồi lấy Cốt Tiễn màu vàng trấn áp để giam cầm, cốt tháp bùng phát hàng vạn tia Thánh quang. Đây là mục tiêu tranh đoạt của cả Nhóc Tỳ lẫn phe Bạch Hổ; cuộc giành giật còn bỏ ngỏ khi Bạch Hổ kéo tới chặn ngang.","nguon":["@c0142"]},{"id":"xe-keo-bao-cu","name":"Xe kéo bảo cụ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ mạnh","soHuu":["Bạch Hổ"],"trangThai":"Đang sử dụng","blurb":"Xe do bốn cường giả khiêng chở Bạch Hổ, thực chất là một bảo cụ mạnh phát sáng phù văn.","detail":"Chiếc xe kéo do bốn cường giả khiêng, chở con Bạch Hổ Nhân tộc cùng hai thiếu nữ thiên tài và một ông lão cảnh giới. Thực chất đây là một bảo cụ mạnh: khi vận hành phát ra phù văn bao phủ cả sơn cốc, dùng để công kích khiến vách tường đổ nát. Bạch Hổ dùng nó kéo tới nơi cốt tháp trắng toát để tranh đoạt.","nguon":["@c0142"]},{"id":"tui-can-khon-da-thu","name":"Túi Càn Khôn (túi da thú)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Lão già (phe Bạch Hổ)"],"trangThai":"Thuộc phe Bạch Hổ","blurb":"Túi da thú làm từ da quý của Thái Cổ di chủng, miệng túi có sức hút vô cùng, chứa được vạn vật không kể nặng nhẹ.","detail":"Túi Càn Khôn được Bạch Hổ ban cho lão già thuộc phe mình, chế tác từ da quý của Thái Cổ di chủng. Hai thiếu nữ thiên tài Nhân tộc, bốn đại hán và lão già hợp lực tế luyện túi này; miệng túi tỏa hào quang, sinh ra sức hút vô cùng mạnh, hút cả tảng đá mười mấy vạn cân, có thể chứa được vạn vật không kể nặng nhẹ. Nhóc Tỳ vô cùng thèm muốn báu vật này, muốn đoạt lấy để nhốt các Thái Cổ di chủng vào bên trong.","nguon":["@c0143"]},{"id":"tieu-thap-trang-cot-thap","name":"Tiểu tháp trắng (Cốt tháp)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Nghi pháp khí Thượng Cổ chư thánh","soHuu":["Nhóc Tỳ"],"trangThai":"Nhóc Tỳ quấn lên tóc, chưa cảm ứng được","blurb":"Tòa cốt tháp trắng tinh uy lực khủng bố; sau khi tự tế luyện trong Địa Hoàng Hỏa thì co lại thành tiểu tháp cao không tới một tấc, trắng như Dương Chi bạch ngọc.","detail":"Ban đầu là tòa cốt tháp trắng tinh lơ lửng trong khe núi rồi trong dung nham, chỉ chấn động nhẹ đã bốc khí lành đẩy lui cốt tiễn và bảo kính. Bị Nhóc Tỳ và Bạch Hổ quấy nhiễu nhiều lần, cốt tháp thức tỉnh (bảo cụ thành tinh), bùng nổ ánh sáng như sao băng hủy diệt cả vùng núi, bắn xuyên vai Bạch Hổ và xuyên ngực lão già. Uy lực vượt xa chí bảo trấn tộc của Côn tộc; lão già nghi nó là pháp khí Thượng Cổ chư thánh, ngay Nhân Hoàng thấy cũng phải thèm. Cốt tháp tự lao vào biển lửa Địa Hoàng Hỏa để tế luyện/lột xác, hút sạch địa hỏa, cuối cùng co lại thành tiểu tháp cao không tới một tấc, to bằng đốt ngón tay, trắng như Dương Chi bạch ngọc, không phản ứng với phù văn hay thần lực. Nhóc Tỳ đành quấn nó lên sợi tóc xem như đồ trang sức.","nguon":["@c0143"]},{"id":"phi-kiem-may-do-tham-phi-di","name":"Phi kiếm mày đỏ thẫm (của Phì Di)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Phì Di","Nhóc Tỳ"],"trangThai":"Nhóc Tỳ đang dùng","blurb":"Thanh phi kiếm mày đỏ thẫm của Phì Di, hóa thành dải lụa đỏ, Nhóc Tỳ dùng để cắt chém nham thạch đào tìm cốt tháp.","detail":"Phi kiếm mày đỏ thẫm vốn của Phì Di, khi thi triển hóa thành dải lụa đỏ thẫm. Nhóc Tỳ dùng thanh phi kiếm này cắt chém nham thạch, đào tìm cốt tháp trong lòng đất sau khi dung nham đọng lại.","nguon":["@c0143"]},{"id":"canh-kim-o","name":"Cánh Kim Ô","aliases":["Bảo phiến vàng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ Thượng Cổ","soHuu":["Chim thần màu vàng"],"trangThai":"mat","blurb":"Bảo cụ Thượng Cổ hình đôi cánh màu vàng, tạo ánh lửa ngập trời và dung nham.","detail":"Đôi cánh màu vàng lơ lửng, xuất thế tại Phân Bảo Nhai tạo ánh lửa và dung nham cuồn cuộn khiến các sinh linh hỗn chiến tranh đoạt. Là bảo phiến màu vàng, tự chọn chủ mới; bị con chim thần màu vàng cướp được bay đi.","nguon":["@c0144","@c0150"]},{"id":"phap-truong-do-nhu-mau","name":"Pháp trượng đỏ như máu","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo Thượng Cổ","soHuu":["Tất Phương"],"trangThai":"dang-co","blurb":"Pháp trượng đỏ như máu dài không tới một thước, phù văn phát tiếng sấm nổ.","detail":"Rực rỡ óng ánh đỏ như máu, dài không tới một thước, phù văn lượn quanh phát ra tiếng sấm nổ; đã hư hại nứt vỡ chỉ còn một đoạn nhỏ, nếu ôn dưỡng tế luyện lại có thể thành chí bảo trấn giáo. Lộ ra từ tảng đá phát sáng, bị Tất Phương nhanh tay thu được.","nguon":["@c0144"]},{"id":"chien-mau-luc-mau","name":"Chiến mâu (lục mâu)","category":"phap-bao","categoryLabel":"Binh khí","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Rễ cây kỳ lạ hóa lục mâu màu xanh lục, sắc bén xuyên sắt đá.","detail":"Rễ cây thực vật kỳ lạ hóa thành lục mâu màu xanh lục, cứng rắn sắc bén xuyên sắt đá, có phù văn nhưng bị khuyết điểm (phù văn ẩn bên trong). Nhóc Tỳ đoạt lấy định tặng cho Đại Tráng, Bì Hầu ở Thạch thôn.","nguon":["@c0144"]},{"id":"kiem-co","name":"Kiếm Cổ","aliases":["Kiếm gãy","kiếm rỉ sét","thanh kiếm gãy"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí Thượng Cổ chư thánh","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Đoạn sắt gãy rỉ sét nặng mấy vạn cân, mang đại sát khí là di vật chư thánh Thượng Cổ.","detail":"Đoạn sắt gãy rỉ sét dài hơn một thước, nửa trên đã gãy thất lạc, chuôi mục nát, nhưng nặng mấy vạn cân, mang đại sát khí khủng khiếp là di vật chư thánh; khi rút ra bốc lên hình ảnh thây chất thành núi máu chảy thành sông. Thân kiếm lạnh lẽo có hoa văn mờ mờ, phát ra tiếng “Kiếm của ta…”. Nhóc Tỳ tìm được để gỡ nguyền rủa Bổ Thiên các, vác lên lưng.","nguon":["@c0145"]},{"id":"tieu-thap-tren-toc","name":"Tiểu tháp","aliases":["Tiểu tháp nhỏ bằng đốt ngón tay","cốt tháp","Tiểu tháp dương chi bạch ngọc"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (uy năng lớn)","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Tiểu tháp nhỏ bằng đốt ngón tay đặt trên tóc Nhóc Tỳ, tự động xua tan sát khí.","detail":"Đặt trên sợi tóc Nhóc Tỳ như vật trang trí; khi Kiếm Cổ tuôn sát khí suýt xoắn nát thân nó, tiểu tháp đột nhiên sáng lên xua tan toàn bộ luồng sát khí mà không ai phát giác, cho thấy uy năng lớn tiềm ẩn chưa khai mở.","nguon":["@c0145","@c0150","@c0162"]},{"id":"hac-sat-chien-truong-co","name":"Hắc sát","cn":"","category":"khac","categoryLabel":"Hiện tượng","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Làn khói đen của chiến trường cổ ăn mòn mọi bảo vật thời Thượng Cổ.","detail":"Bạch Hổ giải thích làn khói đen lượn lờ trên đỉnh Phân Bảo Nhai là hắc sát của chiến trường cổ, ăn mòn mọi bảo vật từ thời Thượng Cổ khiến chúng mục nát dần; nếu Kiếm Cổ còn Linh thì quả là nghịch thiên.","nguon":["@c0145"]},{"id":"cot-hoan-thuong-co","name":"Cốt hoàn Thượng Cổ","cn":"","category":"phap-bao","categoryLabel":"Pháp khí Thượng Cổ","phamCap":"Pháp khí Thượng Cổ","soHuu":["Hỏa Linh Nhi"],"trangThai":"dang-co","blurb":"Vòng bằng xương màu xanh da trời khắc từ bảo cốt động vật, đầy linh tính nhưng thiếu một miếng.","detail":"Chiếc cốt hoàn (vòng bằng xương) màu xanh da trời khắc từ bảo cốt động vật, giống như khắc từ ngọc thạch, đầy linh tính, phù văn phủ kín, phát sáng trấn áp hư không; là pháp khí Thượng Cổ nhưng thiếu một miếng nên không hoàn chỉnh — nếu có thanh không hư hại sẽ thành chí bảo trấn quốc. Hỏa Linh Nhi giành đeo lên cổ tay.","nguon":["@c0146"]},{"id":"chien-mau-28","name":"Chiến mâu (28 thanh)","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Bảo cụ Thái Cổ","soHuu":["Bạch Hổ"],"trangThai":"hong","blurb":"28 thanh chiến mâu trắng bạc do răng nanh Thái Cổ di chủng hóa thành, đè ép trời đất.","detail":"28 thanh chiến mâu trắng bạc bóng loáng do răng nanh Thái Cổ di chủng hóa thành, to như cột chống trời, đầu mâu nhuốm máu, đè ép trời đất; bùng phát phù văn hình thành sát trận vây giết. Bị Kiếm Cổ của Nhóc Tỳ một nhát chém đứt đôi toàn bộ.","nguon":["@c0148"]},{"id":"bao-y-bach-ho","name":"Bảo y Bạch Hổ","cn":"","category":"phap-bao","categoryLabel":"Chiến y","phamCap":"Bảo cụ Thái Cổ","soHuu":["Bạch Hổ"],"trangThai":"hong","blurb":"Chiến y chế từ da tiền bối Thái Cổ di chủng, phòng ngự cực mạnh.","detail":"Chiến y chế từ da tiền bối Thái Cổ di chủng, phòng ngự cực mạnh khó công phá; Long Giao tiễn (Cốt Tiễn màu vàng) phá được tầng ánh sáng bạc tạo khe khiến Bạch Hổ chảy máu, rồi xé bảo y thành từng mảnh.","nguon":["@c0148"]},{"id":"tui-can-khon","name":"Túi Càn Khôn","aliases":["túi da bảo dược Bạch Hổ","túi da thú"],"category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Bảo cụ mạnh nhất của Bạch Hổ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","tenCu":"","blurb":"Túi da thú bảo cụ mạnh nhất của Bạch Hổ, mở miệng hút vạn vật để đoạt binh khí.","detail":"Túi da thú, bảo cụ mạnh nhất của Bạch Hổ, mở miệng túi hút vạn vật để đoạt binh khí đối thủ; bị kiếm khí Kiếm Cổ chặn khí lành. Sau khi Bạch Hổ mất thần lực khống chế, phù văn túi lu mờ ẩn vào trong, bị Nhóc Tỳ chụp đoạt được; Nhóc Tỳ định dùng bắt hết Thái Cổ di chủng trong Bách Đoạn sơn nhét vào.","nguon":["@c0148","@c0152"]},{"id":"bao-an-bach-ho","name":"Bảo ấn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ Thái Cổ","soHuu":["Bạch Hổ"],"trangThai":"hong","blurb":"Bảo cụ Bạch Hổ phun ra từ miệng nện tới, bị kiếm gãy chém nổ tung.","detail":"Bảo cụ Bạch Hổ há miệng phun ra nện tới Nhóc Tỳ, bị Nhóc Tỳ chém Kiếm Cổ làm nổ tung thành một chùm ánh sáng đáng sợ; là một trong các bảo cụ dùng tinh huyết ôn dưỡng tế luyện nhiều năm, nổ tan khiến Bạch Hổ phun máu tươi.","nguon":["@c0148"]},{"id":"kiem-gay-phap-khi-thuong-co","name":"Kiếm gãy (pháp khí Thượng Cổ)","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Pháp khí Thượng Cổ","soHuu":["Nhóc Tỳ (Thạch Hạo)"],"trangThai":"Nhóc Tỳ đang sử dụng","blurb":"Thanh kiếm nát rỉ sét của Nhóc Tỳ nhưng uy lực khủng khiếp, càng đánh càng mạnh, khi vệt rỉ sét tróc ra lộ thân kiếm đen thui.","detail":"Kiếm gãy là pháp khí Thượng Cổ trong tay Nhóc Tỳ (Thạch Hạo), thoạt nhìn chỉ là thanh kiếm nát rỉ sét nhưng uy lực khủng khiếp, đối đầu ngang ngửa với Nguyên Từ Phong của Kim Sí Bằng điểu. Càng đánh càng mạnh: vệt rỉ sét tróc ra để lộ thân kiếm đen thui, ánh kiếm mãnh liệt hơn, uy năng cực hạn tăng dần khiến Kim Sí Bằng điểu khiếp sợ do dự. Khi Nhóc Tỳ rót toàn bộ tinh khí thần vào, thanh kiếm gãy như từ trong giấc ngủ ngàn thu tỉnh dậy, biến thành một vầng thái dương chói lọi, phóng thích toàn lực. Nhóc Tỳ một mực bảo lưu thần uy khó lường của kiếm gãy, gợi mở lai lịch phi thường chưa lộ hết.","nguon":["@c0149"]},{"id":"nguyen-tu-phong","name":"Nguyên Từ Phong","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo (tế luyện từ Tế Linh Nguyên Từ Sơn)","soHuu":["Kim Sí Bằng điểu"],"trangThai":"hong","blurb":"Ngọn núi mang từ tính (nam châm) do Kim Sí Bằng điểu phun ra, khắc chế binh khí kim loại, hút chặt binh khí và bảo cụ đối thủ.","detail":"Nguyên Từ Phong (còn gọi Nguyên Tử Phong / Từ Sơn) là bảo cụ của Kim Sí Bằng điểu, hình dạng một hòn đá đầy bụi bẩn phun ra biến thành ngọn núi khổng lồ mang từ tính. Chuyên khắc chế binh khí kim loại, hút chặt và trấn áp kiếm gãy cùng các bảo cụ đối thủ, tia sáng nguyên từ có thể xuyên thủng cường giả; là chí bảo dù không phải pháp khí Thượng Cổ. Bảo cụ này nguyên là một Tế Linh danh chấn đại địa tên Nguyên Từ Sơn, từng bị một con Đại Bằng điểu màu vàng đánh bại rồi tế luyện thành bảo cụ. Sư Tử chín đầu và tộc ba mắt nhận ra lai lịch của nó.","nguon":["@c0149","@c0150"]},{"id":"bao-phien-vang-canh-kim-o","name":"Bảo phiến vàng (cánh Kim Ô)","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Pháp khí Thượng Cổ","soHuu":["Kim Sí Bằng điểu"],"trangThai":"Kim Sí Bằng điểu đang sử dụng","blurb":"Cây quạt toàn thân vàng óng lấy cánh Kim Ô tế luyện, có thể biến thành cánh thần vỗ ra thần hỏa; đoạt được trên Phân Bảo Nhai.","detail":"Bảo phiến vàng là pháp khí Thượng Cổ của Kim Sí Bằng điểu, một cây quạt toàn thân vàng óng lấy cánh của Kim Ô tế luyện mà thành, xen lẫn lông chim Kim Ô thuần huyết. Khi tung ra, thần hỏa bộc phát, đại hỏa ngập trời khiến mặt đất hóa thành dung nham. Bảo phiến còn có thể biến thành một chiếc cánh thần to lớn vỗ xuống, mang theo thần hỏa và phù văn đáng sợ. Đây là pháp khí sót lại của Thượng Cổ chư thánh, được Kim Sí Bằng điểu đoạt được trên Phân Bảo Nhai. Nó mạnh hơn cả kiếm gãy nhưng vẫn từng trúng một tia kiếm khí của Nhóc Tỳ. 「Lấy cánh của Kim Ô tế luyện mà thành, bảo cụ thật mạnh mẽ!」","nguon":["@c0149"]},{"id":"hac-oa-noi-den","name":"Hắc Oa","cn":"","aliases":["Nồi đen"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ","soHuu":["Đại Hồng Điểu"],"trangThai":"dang-co","blurb":"Bảo cụ của Đại Hồng Điểu luyện chế từ vỏ trứng, ngậm trong miệng tỏa vạn hào quang cứng rắn đối chọi ác điểu.","detail":"Bảo cụ của Đại Hồng Điểu luyện chế từ vỏ trứng, ngậm trong miệng tỏa vạn hào quang, khí lành, cứng rắn để đối chọi ác điểu; bị Nhóc Tỳ giật lấy nện lên đầu Đại Hồng Điểu. Nghĩa đen là cái nồi đen, nghĩa bóng là bị oan ức.","nguon":["@c0151"]},{"id":"mau-huyet-kim-si-dai-bang","name":"Máu huyết Kim Sí Đại Bằng","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Tinh huyết bảo dược","soHuu":[],"trangThai":"dang-co","blurb":"Máu của chim thần bán huyết, bảo dược hiếm có chứa vô hạn tinh hoa thần thánh, dùng ninh nấu bồi bổ thân thể.","detail":"Máu huyết của Kim Sí Đại Bằng — chim thần bán huyết — là bảo dược hiếm có, giá trị khó tưởng tượng; Người phong ấn khuyên tận dụng, cả đám tìm suối trong lột da rửa thịt ninh nấu di chủng bồi bổ thân thể; Hỏa Linh Nhi biết vài phương thuốc cổ giúp tinh huyết phát huy dược hiệu tốt nhất, dù có thể chọc giận tộc Kim Bằng.","nguon":["@c0151"]},{"id":"canh-ho-cot-bach-ho","name":"Canh hổ cốt Bạch Hổ","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Thực dược","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Nấu từ chân sau Bạch Hổ ba canh giờ, nước canh đặc sệt óng ánh, ăn vào cảm giác lỗ chân lông thông thấu.","detail":"Canh nấu từ chân sau Bạch Hổ ba canh giờ, nước canh đặc sệt óng ánh, khi đến gần hiện hư ảnh bạch hổ, ăn vào cảm giác lỗ chân lông thông thấu; Nhóc Tỳ dùng bảo thuật làm tan cả xương thành chất lỏng, cả đám tranh nhau uống. Vài con Tử Điêu, Hỏa Nha uống xong đột phá bình cảnh tăng thêm một tầng.","nguon":["@c0152"]},{"id":"thit-bao-vien","name":"Thịt Bạo Viên","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Huyết nhục bảo dược","soHuu":[],"trangThai":"da-dung","blurb":"Huyết nhục bảo dược tinh khí cường đại, giúp di chủng liền xương, khép vết thương, thuần huyết, đột phá.","detail":"Thịt của Bạo Viên (Cự viên, cổ huyết đậm đặc tỏa hào quang đen) là huyết nhục bảo dược tinh khí cường đại; đám di chủng ăn vào xương gãy liền lại, vết thương khép, Tử Điêu ăn hơn ngàn cân cảm thấy sắp đột phá, Sư Tử chín đầu máu trở nên thuần huyết hơn.","nguon":["@c0152"]},{"id":"cot-dao-xanh-nhat-ngu-lao","name":"Cốt đao màu xanh nhạt","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Vũ khí","soHuu":["Ngũ lão"],"trangThai":"dang-co","blurb":"Cốt đao của Ngũ lão, đao khí phóng hơn mười thước ép cổ thụ cự thạch thành bột.","detail":"Cốt đao màu xanh nhạt của Ngũ lão, đao khí phóng hơn mười thước ép cổ thụ cự thạch thành bột; dùng chống sinh linh ba đầu Linh tộc nhưng bị đánh văng.","nguon":["@c0153"]},{"id":"thong-linh-than-hoa","name":"Thông Linh Thần Hoa","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Thánh dược","soHuu":[],"trangThai":"mat","blurb":"Loại thánh dược trong Thần viên, phấn hoa của nó có thể khiến vật mở linh trí biết nói.","detail":"Thông Linh Thần Hoa là loại thánh dược trong Thần viên (Bách Thảo viên); phấn hoa của nó có thể khiến vật (như tảng đá) dính vào mà mở linh trí biết nói.","nguon":["@c0153","@c0154","@c0158"],"aliases":["Thông Linh Hoa"]},{"id":"linh-huyet-linh-toc","name":"Linh huyết Linh tộc","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Linh huyết","soHuu":[],"trangThai":"dang-co","blurb":"Huyết của cường giả Linh tộc cực quý, có thể giúp ngộ đạo.","detail":"Linh huyết của cường giả Linh tộc cực quý giá, có thể giúp ngộ đạo; cánh tay cụt của sinh linh ba đầu Linh tộc có linh huyết mạnh mẽ, có thể ngưng luyện, giá trị quý hơn linh huyết Linh tộc ánh bạc Nhóc Tỳ từng lấy trước đó.","nguon":["@c0153"]},{"id":"day-leo-tim-thanh-tinh","name":"Dây leo tím thành tinh","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Linh dược","soHuu":[],"trangThai":"hong","blurb":"Linh dược Thần viên thành tinh, dài mười thước như giao long tím, có linh trí, chủ động tấn công người xâm nhập.","detail":"Dây leo tím là linh dược trong Thần viên đã thành tinh sinh ra linh trí, dài mười thước như giao long tím, cắm rễ trong nham thạch, chủ động tấn công người xâm nhập; van xin Nhóc Tỳ tha nhưng vẫn phản kích bằng nhánh khác, bị Nhóc Tỳ giật đứt nhổ tận gốc.","nguon":["@c0153"]},{"id":"da-than-thach","name":"Đả Thần Thạch","cn":"","aliases":["ngoan thạch","hòn đá nhỏ","viên đá thần nhỏ"],"category":"khac","categoryLabel":"Đá kỳ vật","phamCap":"Nghi kỳ vật Thượng Cổ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Tảng đá biết nói cực kỳ cứng rắn, đập một lần trúng một lần, không sứt mẻ dù đập mạnh; sinh linh nghi là Đả Thần Thạch trong truyền thuyết.","detail":"Nhóc Tỳ dùng ngoan thạch làm vũ khí ném đập Hoàng Kim thú, 'đập cái nào trúng cái đó'; dù đập rất mạnh vẫn không hề sứt mẻ, chỉ gào khóc thảm thiết. Có sinh linh nghi đây là Đả Thần Thạch trong truyền thuyết — loại đá vốn chỉ có vài khối, bị Thượng Cổ đại năng lấy đi luyện chí bảo. Danh tính Đả Thần Thạch hiện chỉ là suy đoán của các sinh linh.","nguon":["@c0155","@c0157","@c0159"]},{"id":"bat-lao-tuyen-tuyen-tri","name":"Bất Lão Tuyền (tuyền trì)","cn":"","aliases":["Bất Lão Thần Tuyền","Bất Lão Tuyền Trì","Tuyền trì màu vàng kim"],"category":"khac","categoryLabel":"Thần trì / Kỳ vật","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Ao thần trì rộng một trượng vuông tỏa kim quang rực rỡ như thái dương, mục tiêu tranh đoạt của các sinh linh; nằm trong trường vực kinh khủng.","detail":"Cái ao Bất Lão Tuyền rộng một trượng vuông tỏa quang huy vàng chói mắt như thái dương, khiến đất trời ráng lửa mênh mông. Nhiều sinh linh hình người, chim, thú cố tiến lại gần nhưng bị trường vực cực kỳ kinh khủng cản, còn ở ngoài mấy trượng. Nhóc Tỳ tính chờ thiếu nữ tóc tím lấy được rồi mới ra tay đoạt.","nguon":["@c0155"]},{"id":"tui-da-bao-duoc","name":"Túi da bảo dược","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược / Túi chứa","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Túi da chứa hai ba chục gốc bảo dược, trong đó sáu bảy cây hoàn hảo, Nhóc Tỳ đoạt được từ Hoàng Kim thú.","detail":"Túi da chứa chừng hai ba chục gốc bảo dược, trong đó có sáu bảy cây hoàn hảo không sây sát gì. Nhóc Tỳ tự nhặt lấy sau khi đập ngất Hoàng Kim thú.","nguon":["@c0155"]},{"id":"sung-hoang-kim-thu","name":"Sừng Hoàng Kim thú","cn":"","aliases":["sừng Thần bộc thông linh"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Hai sừng vàng kim ánh vàng xán lạn của Hoàng Kim thú, mài thành bột làm thuốc dẫn hiếm có.","detail":"Hai cái sừng vàng kim của Hoàng Kim thú (Thần bộc thông linh), toả linh khí nồng đậm. Khi mài thành bột dùng làm thuốc dẫn hiếm có. Bị Nhóc Tỳ dùng ngoan thạch đập bẻ đoạt lấy rồi đập ngất chủ nhân sừng.","nguon":["@c0156"]},{"id":"huyet-nhuc-bao-duoc-chu-kien","name":"Huyết nhục bảo dược (của Chư Kiền)","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bảo dược","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Tảng huyết nhục Thạch Hạo xé được từ tay Chư Kiền, cất vào túi làm bảo dược.","detail":"Tảng huyết nhục bảo dược Thạch Hạo vật lộn xé được từ tay hung thú Chư Kiền, nhét vào túi tuyên bố muốn ăn sạch nó.","nguon":["@c0157"]},{"id":"bat-lao-tuyen-rong-nho","name":"Bất Lão Tuyền (rồng nhỏ)","aliases":["Bất Lão Thần Tuyền","Bất Lão Tuyền Trì"],"category":"khac","categoryLabel":"Bảo vật","phamCap":"Thần vật Thượng Cổ","soHuu":[],"trangThai":"mat","blurb":"Bảo vật ở thần trì đã hóa thành con rồng nhỏ màu vàng dài hơn một thước đang lột xác định hóa hình, nên thần tuyền khô cạn.","detail":"Không còn là chất lỏng vàng kim mà đã hóa thành con rồng nhỏ màu vàng dài hơn một thước đang lột xác định hóa hình, khiến thần tuyền khô cạn chỉ còn bùn cát. Bị Thạch Hạo cắn đứt đuôi, rồng gầm thét phá tung tuyền trì rồi hóa hào quang bỏ chạy; đuôi rồng bị Thạch Hạo giữ lại.","nguon":["@c0157"]},{"id":"bun-cat-than-tri","name":"Bùn cát thần trì","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Bùn cát óng ánh ẩm ướt tỏa hào quang vàng kim, phóng thích sức mạnh thần thánh bất hủ, là phần sót lại của Bất Lão Tuyền.","detail":"Bùn cát long lanh ẩm ướt tỏa hào quang vàng kim, nguồn phát ra các sóng sức mạnh thần thánh bất hủ; phần còn sót của Bất Lão Tuyền sau khi khô cạn. Được Ngoan thạch và Thạch Hạo tranh nhau ăn.","nguon":["@c0157"]},{"id":"duoi-rong-nho-bat-lao-tuyen","name":"Đuôi rồng nhỏ","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Đuôi con rồng vàng (Bất Lão Tuyền) bị Thạch Hạo cắn đứt và giữ lại khi rồng bỏ chạy.","detail":"Đuôi con rồng vàng lột xác từ Bất Lão Tuyền, bị Thạch Hạo cắn đứt lìa; cuối cùng Thạch Hạo chụp lấy giành giữ khi rồng hóa hào quang bỏ chạy.","nguon":["@c0157"]},{"id":"binh-ngoc-nhot-rong-bat-lao-tuyen","name":"Bình ngọc nhỏ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Vật chứa","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Bình ngọc nhỏ Nhóc Tỳ dùng đậy chặt năm con rồng nhỏ Bất Lão Tuyền để không chạy.","detail":"Theo lời ngoan thạch, đậy chặt năm giọt Bất Lão Tuyền hóa thành năm con rồng nhỏ trong bình ngọc thì rồng không chạy được; Nhóc Tỳ nhét năm con rồng vào rồi đậy nắp.","nguon":["@c0158"]},{"id":"cat-than-bun-cat-vang","name":"Cát thần (bùn cát màu vàng)","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Thần tính","soHuu":["Nhóc Tỳ"],"trangThai":"da-dung","blurb":"Cát thần Nhóc Tỳ nhai để luyện hóa nâng thực lực; Đả Thần Thạch nói loại này khó tiêu hóa.","detail":"Bùn cát thần màu vàng có thần tính, Nhóc Tỳ nhai và luyện hóa toàn bộ để mong lớn thêm hai ba tuổi, nâng cao thực lực. Đả Thần Thạch than loại cát này khó tiêu hóa.","nguon":["@c0160"]},{"id":"nam-dong-thien-chim-than","name":"Năm Động Thiên chim thần của Thạch Nghị","category":"khac","categoryLabel":"Khác","phamCap":"Trấn tộc","soHuu":["Thạch Nghị"],"trangThai":"dang-co","blurb":"Năm Động Thiên phát sáng quanh Thạch Nghị, mỗi cái tẩm bổ một sinh linh chí tôn hóa từ mảnh phù văn.","detail":"Quanh người Thạch Nghị hiện ra năm Động Thiên, mỗi Động Thiên tẩm bổ một sinh linh chí tôn Thái Cổ hóa từ một mảnh phù văn: Khổng Tước ngũ sắc, Bệ Ngạn, Kim Sí Đại Bằng (Kim Bằng)... Là dị tượng phù văn biểu hiện bảo thuật luyện đến cảnh giới xuất thần nhập hóa.","nguon":["@c0160"]},{"id":"chi-ton-cot-nhoc-ty","name":"Chí Tôn Cốt (trong ngực Thạch Hạo)","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Thần cốt cực phẩm","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Đoạn thần cốt (thụ cốt/xương ức) trong ngực Thạch Hạo; Bảo cốt nguyên bản đã bị cướp cấy vào Thạch Nghị, nay khí tức Chí Tôn Cốt thức tỉnh tái sinh.","detail":"Đoạn xương thần thánh trong ngực Thạch Hạo, mang khí tức Chí Tôn quen thuộc từ bé nó. Bảo cốt nguyên bản của nó đã bị cướp cấy vào thân thiếu niên thần thánh Thạch Nghị khiến Thạch Hạo lưu lạc thân nhân ly biệt. Chương này khí tức Chí Tôn Cốt thức tỉnh, hào quang hóa thành mặt trời nhỏ, bên trong tựa một đứa trẻ lóng lánh ngồi xếp bằng — một vị Chí Tôn được thai nghén; toàn bộ Thái Nhất Chân Thủy và tinh huyết ngưng tụ về ngực nó, mở ra hy vọng tái sinh một Chí Tôn Cốt mới.","nguon":["@c0135"]},{"id":"noi-den-trung-chim-dai-hong-dieu","name":"Nồi đen (trứng chim mài giũa)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại Hồng Điểu"],"trangThai":"dang-co","blurb":"Pháp bảo của Đại Hồng Điểu, không phải nồi sắt mà do trứng chim mài thành, dùng hấp thu và phong ấn nước thần.","detail":"Đen bóng như mặc ngọc, phù văn chằng chịt cùng lôi điện tia lửa. Đại Hồng Điểu phun ra để hấp thu Thái Nhất Chân Thủy bị phung phí, nhiều lần nuốt-nhả nước thần.","nguon":["@c0135"]},{"id":"kiem-gay","name":"Kiếm gãy","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Thanh kiếm gãy Nhóc Tỳ rút ra bổ thẳng, kiếm khí vừa thô vừa to.","detail":"Trong trận giao đấu với Tất Phương, Nhóc Tỳ rút kiếm gãy bổ thẳng, kiếm khí vừa thô vừa to góp phần làm nổ tung cả vùng núi và tổ chim.","nguon":["@c0161"]},{"id":"qua-trung-than-mau-bac","name":"Quả trứng thần màu bạc","category":"khac","categoryLabel":"Di bảo","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Trứng của một di chủng mạnh, phát sáng như bị hỏa diễm thiêu đốt, ẩn chứa tinh hoa; nếu ấp nở đại biểu một loại bảo thuật kinh khủng.","detail":"Quả trứng của một di chủng mạnh, phát sáng như bị hỏa diễm thiêu đốt; bị Tất Phương hút gần nửa chất lỏng rồi bị Nhóc Tỳ dùng túi Càn Khôn thu vào. Nếu ấp nở đại biểu một loại bảo thuật kinh khủng.","nguon":["@c0161"]},{"id":"bong-tai-than-kim","name":"Bông tai thần kim","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"bi-cuop","blurb":"Bông tai màu tím luyện từ thần kim của thiếu nữ áo tím, bị Nhóc Tỳ cắn đứt cướp đi.","detail":"Chiếc bông tai màu tím luyện từ thần kim, phát bảo huy và thần mang chống lực hút của túi Càn Khôn; bị tiểu tháp đụng làm ảm đạm rồi Nhóc Tỳ cắn đứt cướp về.","nguon":["@c0162"]},{"id":"vong-than-hoan","name":"Vòng thần hoàn","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Không rõ","soHuu":["Thiếu nữ áo tím"],"trangThai":"dang-co","blurb":"Vòng thần hoàn óng ánh ở cổ tay thiếu nữ áo tím dùng đánh giết.","detail":"Vòng thần hoàn óng ánh ở cổ tay dùng để đánh giết, nhưng bị Đả Thần Thạch cắn giam cầm nên không phát huy được uy lực.","nguon":["@c0162"]},{"id":"sung-thu-mau-vang","name":"Sừng thú màu vàng","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Không rõ","soHuu":["Thiếu nữ áo tím"],"trangThai":"dang-co","blurb":"Chiếc sừng thú nhỏ óng ánh phát thần quang nghiền nát mặt đất và bảo cốt.","detail":"Chiếc sừng thú nhỏ nhắn óng ánh trong tay thiếu nữ áo tím, phát thần quang nghiền nát mặt đất và bảo cốt quanh tổ chim khi nàng phá hang.","nguon":["@c0162"]},{"id":"bao-kinh-than-nu","name":"Bảo kính","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Không rõ","soHuu":["Thiếu nữ áo tím"],"trangThai":"dang-co","blurb":"Chiếc bảo kính sáng rực xuất hiện trước ngực thiếu nữ khi đối chiến.","detail":"Chiếc bảo kính sáng rực xuất hiện trước ngực thiếu nữ áo tím khi nàng nổi thịnh nộ liều mạng đối chiến với Nhóc Tỳ, khiến cả tòa núi nổ tung.","nguon":["@c0162"]},{"id":"hac-giao-thao","name":"Hắc Giao thảo","cn":"","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Bốn gốc linh dược mọc bên đầm nước lạnh, toàn thân đen bóng tỏa mùi thơm.","detail":"Bốn gốc Hắc Giao thảo mọc bên đầm nước lạnh, toàn thân đen bóng, tỏa mùi thơm; sinh nơi từng có giao thú. Nhóc Tỳ đào được cả bốn gốc bỏ vào túi Càn Khôn.","nguon":["@c0162"]},{"id":"ngan-vu-thao","name":"Ngân Vũ thảo","cn":"","category":"dan-duoc","categoryLabel":"Linh dược cực phẩm","phamCap":"Cực phẩm","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Linh dược cực phẩm năm chiếc lá trắng bạc phát thần huy, có dấu hình lông vũ.","detail":"Ngân Vũ thảo mọc trước miệng hang, năm chiếc lá trắng bạc phát thần huy có dấu hình lông vũ; truyền thuyết nếu sinh trưởng đủ năm sẽ tiến thêm một bước, bắt đầu lột xác tiến hóa. Nhóc Tỳ thu vào túi Càn Khôn.","nguon":["@c0162"]},{"id":"bao-huyet-than-nu","name":"Bảo huyết của thiếu nữ áo tím","cn":"","category":"khac","categoryLabel":"Tài nguyên","phamCap":"Không rõ","soHuu":["Thiếu nữ áo tím"],"trangThai":"da-dung","blurb":"Máu ứa từ vành tai thiếu nữ bị cắn, thơm ngọt, Nhóc Tỳ hút mạnh.","detail":"Máu ứa ra từ vành tai bị Nhóc Tỳ cắn, thơm ngọt khác thường; Nhóc Tỳ hút mạnh, chưa rõ là loại bảo huyết gì.","nguon":["@c0162"]},{"id":"ken-phat-sang","name":"Kén phát sáng","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Cái kén không ngừng phát sáng trong tổ chim thứ hai, bị Nhóc Tỳ cướp đi.","detail":"Trong động thiên thứ hai lộ ra sau khi núi nổ tung có tổ chim thứ hai chứa một cái kén không ngừng phát sáng; chưa rõ bên trong là sinh linh gì. Nhóc Tỳ vọt tới nâng kén rồi bỏ chạy.","nguon":["@c0162"]},{"id":"bong-tai-bao-chau-tim","name":"Bông tai/bảo châu tím","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Chiến lợi phẩm cướp từ thiếu nữ áo tím, có phù văn tạo màng bảo vệ và phóng kiếm khí.","detail":"Bảo châu to bằng quả trứng bồ câu, màu tím nhiều sắc xoay chuyển; khi thúc dục thì hiện phù văn tạo màng ánh sáng bảo vệ và phóng kiếm khí. Do Đả Thần Thạch cắn vành tai thiếu nữ áo tím cướp được.","nguon":["@c0163"]},{"id":"cai-ken-phat-sang","name":"Cái kén phát sáng","aliases":["Kén phát sáng"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Cái kén như có thần tằm ẩn trong, tài liệu quý không kém Thiên Tằm Ti.","detail":"Kén như có thần tằm ẩn trong; Đả Thần Thạch nói không kém Thiên Tằm Ti, may quần áo thì trần thế bất nhiễm thủy hỏa bất xâm. Nhóc Tỳ trộm được và cất vào Túi Càn Khôn, chưa phá kén để lộ sinh vật bên trong.","nguon":["@c0163"]},{"id":"soi-day-xich-mau-vang","name":"Sợi dây xích màu vàng","aliases":["Dây chuyền màu vàng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Bảo cụ Nhóc Tỳ tế luyện, quấn quanh cổ tay làm bảo vệ.","detail":"Sợi dây xích màu vàng Nhóc Tỳ tế luyện, kéo dài quấn quanh cổ tay; khi nguy hiểm là đại sát khí, tạo màng ánh sáng bảo vệ chống phù văn của Cổ thụ Thiết Huyết.","nguon":["@c0163"]},{"id":"than-mau-than-hau","name":"Thần mâu của thần hầu","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Không rõ","soHuu":["Thần Hầu vương"],"trangThai":"dang-co","blurb":"Cây thần mâu nặng mấy vạn cân của thần hầu vàng.","detail":"Cây thần mâu nặng mấy vạn cân do thần hầu vàng cao 1m5 sử dụng, ném nát đuôi Li Long ở Bách Đoạn sơn.","nguon":["@c0163"]},{"id":"dao-tien-bon-goc-bao-duoc","name":"Đào tiên (bốn gốc bảo dược)","category":"dan-duoc","categoryLabel":"Đan dược / Bảo dược","phamCap":"Thánh dược (sắp lột xác)","soHuu":[],"trangThai":"dang-co","blurb":"Lão thánh dược của Bách Thảo Viên, tái sinh thành bốn gốc bảo dược trong bảo địa thần hầu, sắp lột xác thành thánh dược.","detail":"Cây đào tiên vốn là lão thánh dược của Bách Thảo Viên, sinh trưởng lâu hơn cả Thông Linh Thần Hoa. Vì muốn xây nền tảng như Thần linh mà dùng quá nhiều tinh hoa thiên địa nên chết đi, để lại bốn hạt giống chứa toàn bộ tinh hoa và lạc ấn, tái sinh thành bốn gốc cao hơn nửa người. Thân lá màu bạc phát sáng như ngọn lửa bạc, mỗi cây có vài quả đào bạc chấm vàng kim tỏa mùi thơm. Được linh dịch trong hồ tẩm bổ, sắp lột xác thành thánh dược — chỉ một cây thành, ba cây còn lại hóa tro. Ăn có thể khiến người thoát thai hoán cốt.","nguon":["@c0164"]},{"id":"tam-tham-than-da-hu-khong-thu","name":"Tấm thảm thần (da Hư Không thú)","category":"phap-bao","categoryLabel":"Bảo cụ tàng hình","phamCap":"Bảo vật Nhân Hoàng ban","soHuu":["Hỏa Linh Nhi"],"trangThai":"dang-co","blurb":"Bảo cụ tàng hình làm từ da Hư Không thú thời Thượng Cổ, do Nhân Hoàng Hỏa quốc ban cho Hỏa Linh Nhi phòng thân.","detail":"Làm từ da Hư Không thú thời Thượng Cổ, có thể ẩn tàng vào thiên địa không bị phát hiện. Là bảo vật của Nhân Hoàng Hỏa quốc ban cho con gái sủng ái Hỏa Linh Nhi phòng thân. Trên thảm có mâm bạch ngọc đựng thịt nướng và trái cây; giúp cả nhóm thoát thú triều và tiếp cận bảo địa thần hầu quan sát bốn cây đào tiên.","nguon":["@c0164"]},{"id":"thuyen-xuyen-van","name":"Thuyền Xuyên Vân","category":"phap-bao","categoryLabel":"Bảo cụ di chuyển","phamCap":"Không rõ","soHuu":["Chim Loan năm màu"],"trangThai":"dang-co","blurb":"Bảo cụ di chuyển của chim Loan năm màu, tế luyện từ bảo cốt năm màu, tốc độ cực nhanh.","detail":"Của chim Loan năm màu, tế luyện từ bảo cốt năm màu, tốc độ cực nhanh, giúp cả nhóm trốn thoát khỏi Cầm vương và Thú vương trong lúc thú triều bộc phát ở Bách Đoạn sơn.","nguon":["@c0164"]},{"id":"chien-mau-vang-khi","name":"Chiến mâu vàng","category":"than-khi","categoryLabel":"Binh khí","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Thanh chiến mâu màu vàng trong tay con khỉ, bổ thẳng xuống dãy núi khi trận chiến giành thánh dược bùng nổ.","detail":"Thanh chiến mâu màu vàng trong tay một con khỉ đạp lưng chim khổng lồ; con khỉ cầm mâu bổ thẳng xuống dãy núi khi bắt đầu đánh nhau, mở màn trận đại chiến giành thánh dược.","nguon":["@c0164"]},{"id":"ho-linh-dich-bao-dia","name":"Hồ linh dịch","category":"khac","categoryLabel":"Linh vật","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Hồ nhỏ trong xanh giữa tịnh thổ do linh khí kết tinh thành chất lỏng, tẩm bổ bốn cây đào tiên.","detail":"Hồ nhỏ trong xanh giữa vùng tịnh thổ bồng lai của bảo địa thần hầu, do linh khí kết tinh thành chất lỏng; linh dịch trong hồ tẩm bổ bốn cây đào tiên khiến chúng sắp lột xác thành thánh dược.","nguon":["@c0164"]},{"id":"ruou-hau-nhi","name":"Rượu Hầu Nhi","cn":"猴儿酒","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Tuyệt thế bảo dược","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Tuyệt thế bảo dược là chất lỏng long lanh như ngọc tủy chứa trong hốc thân cây khô, ủ từ nhiều linh dược và có hương đào tiên.","detail":"Chất lỏng long lanh như ngọc tủy chứa trong hốc thân cây khô có phù văn khủng bố bảo vệ; ủ từ nhiều linh dược (Xích Lan, Hắc Ngọc Liên, Tuyết Ngọc Sâm, Xích Giao...) và có hương đào tiên. Uống một ngụm khiến trời đất quay cuồng, hào quang phát ra từ lỗ chân lông, dược hiệu cực mạnh. Nhóc Tỳ tin nó sẽ giúp mở được Động Thiên thứ chín và khôi phục sức sống cho Chí Tôn Cốt.","nguon":["@c0165","@c0166","@c0170","@c0176"]},{"id":"nam-dau-khi","name":"Nấm Đầu Khỉ","cn":"猴头菇","category":"linh-khi","categoryLabel":"Linh dược","phamCap":"Sinh dược / linh dược","soHuu":[],"trangThai":"dang-co","blurb":"Sinh dược hình đầu khỉ mọc trên cổ thụ phát sáng, hơn mười cây, tản mát linh khí.","detail":"Sinh dược hình đầu khỉ mọc trên cổ thụ phát sáng nơi tịnh thổ, hơn mười cây, tản mát linh khí. Khi thành linh dược là món ăn trân quý; Nhóc Tỳ mê ăn nhưng bị Sói con ngăn để dẫn tới Rượu Hầu Nhi.","nguon":["@c0165","@c0166"]},{"id":"bao-an-nam-mau","name":"Bảo ấn năm màu","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Bảo ấn năm màu do Khổng Tước năm màu phun ra, biến lớn đập nát cả tòa núi.","detail":"Pháp bảo Khổng Tước năm màu phun ra, biến lớn bay thẳng tới linh hồ để cướp thánh dược, uy lực đập nát cả tòa núi.","nguon":["@c0165"]},{"id":"sung-mau-vang-thieu-nu-toc-tim","name":"Sừng màu vàng","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thiếu nữ tóc tím"],"trangThai":"dang-co","blurb":"Chiếc sừng màu vàng thiếu nữ tóc tím cầm vẽ trên không phá bỏ cấm chế phù văn.","detail":"Pháp bảo hình chiếc sừng màu vàng; thiếu nữ tóc tím cầm chặt trong tay nhẹ nhàng vẽ trên không trung, lập tức cả mảng cấm chế phù văn bị phá bỏ, mở đường cho nhóm vào tịnh thổ.","nguon":["@c0165"]},{"id":"dao-tien-mau-bac","name":"Đào tiên màu bạc","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Tiểu thánh dược","soHuu":[],"trangThai":"dang-co","blurb":"Bốn cây đào tiên bạc mọc ven linh hồ trong tịnh thổ, quả trắng bạc tỏa thơm, tia điện lượn quanh; mục tiêu tranh đoạt của các vương giả và sinh linh thuần huyết.","detail":"Bốn cây đào tiên màu bạc mọc ven linh hồ trong tịnh thổ, quả trắng bạc tỏa hương thơm, tia điện lượn quanh, thuộc hàng tiểu thánh dược chỉ một bước cách thánh dược. Đây là mục tiêu tranh đoạt kịch liệt của các vương giả cùng những sinh linh thuần huyết như Chư Kiền, Li Long, Tất Phương, Liệt Thiên Ma Điệp và thiếu niên Thạch Nghị. Trong hai hốc rượu Nhóc Tỳ thu được cũng có kèm đào tiên bạc.","nguon":["@c0166"]},{"id":"luoi-sao-li-long","name":"Lưới sao của Li Long","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ","soHuu":["Li Long"],"trangThai":"dang-co","blurb":"Lưới lớn mặt có nhiều ngôi sao lấp lánh, dung luyện từ lân phiến Li Long thuần huyết và gân cốt cổ thú.","detail":"Lưới sao là bảo cụ của Li Long, mặt lưới điểm nhiều ngôi sao lấp lánh, được dung luyện từ lân phiến của Li Long thuần huyết cùng gân cốt cổ thú. Trong cuộc tranh đoạt đào tiên, Li Long tung lưới chụp và trọng thương một thần hầu thủ lĩnh.","nguon":["@c0166"]},{"id":"tam-sat-than-hau","name":"Tấm sắt thần của thần hầu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ","soHuu":[],"trangThai":"dang-co","blurb":"Tấm sắt lượn ánh sáng đen, bảo cụ của thần hầu thủ lĩnh dùng nện Thạch Nghị.","detail":"Tấm sắt thần là bảo cụ của một thần hầu thủ lĩnh, bề mặt lượn ánh sáng đen; được dùng để nện thiếu niên Thạch Nghị trong cuộc tranh đoạt đào tiên ven linh hồ.","nguon":["@c0166"]},{"id":"bao-cu-khi-bat-hu-chu-kien","name":"Bảo cụ khí bất hủ của Chư Kiền","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ","soHuu":["Chư Kiền"],"trangThai":"dang-co","blurb":"Chùm ánh sáng rực rỡ có bảo cụ ở giữa, tỏa khí tức bất hủ, trấn áp bầy khỉ.","detail":"Bảo cụ của Chư Kiền phát ra chùm ánh sáng rực rỡ với bảo cụ ở trung tâm, tỏa khí tức bất hủ; trong cuộc tranh đoạt đào tiên, nó được dùng để trấn áp bầy khỉ giữ bốn cây đào tiên bạc.","nguon":["@c0166"]},{"id":"phap-truong-chay-den","name":"Pháp trượng cháy đen","category":"phap-bao","categoryLabel":"Pháp bảo / Cổ Khí","phamCap":"Không rõ","soHuu":["Bồ Ma thụ"],"trangThai":"dang-co","blurb":"Bảo cụ của Bồ Ma thụ, cháy đen, mang khí tức nhật nguyệt tinh thần bị trấn áp; tương truyền là đoạn binh khí của gốc Ma thụ từng giết chết thần linh.","detail":"Nhóc Tỳ dùng kiếm gãy chém lộ ra bảo cụ này của Bồ Ma thụ — một pháp trượng cháy đen mang khí tức nhật nguyệt tinh thần. Đây được cho là một đoạn binh khí của gốc Ma thụ khi xưa, tương truyền đã từng giết chết thần linh. Khi Bồ Ma thụ rút lui đã thu hồi cả pháp trượng.","nguon":["@c0167"]},{"id":"bao-duoc-huyet-nhuc","name":"Bảo dược huyết nhục","category":"dan-duoc","categoryLabel":"Đan dược / Vật phẩm","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Huyết nhục của các sinh linh thuần huyết / bảo thể, rất trân quý, kích thích tính hung ác của đàn khỉ vàng.","detail":"Trong đại chiến tranh đoạt thánh dược, máu tươi (huyết nhục bảo dược) của các sinh linh thuần huyết văng đầy khiến đàn khỉ vàng bị kích thích trở nên hung ác hơn.","nguon":["@c0167"]},{"id":"dao-tien-mau-bac-thanh-duoc","name":"Đào tiên màu bạc","aliases":["thánh dược"],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Thánh dược","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Bốn gốc cây nhỏ màu bạc mọc quả đào bạc, là thánh dược quý mà mọi sinh linh tranh đoạt.","detail":"Bốn gốc đào tiên màu bạc là thánh dược cực quý sinh trưởng bên linh hồ tịnh thổ. Trong cuộc đại chiến, Nhóc Tỳ cắn được một khúc thân có quả đào bạc rồi cuối cùng nhờ cái kén trong túi Càn Khôn đoạt trọn một gốc.","nguon":["@c0168"]},{"id":"binh-trang-noan-thach-nghi","name":"Bình trắng noãn","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Nghị"],"trangThai":"dang-co","blurb":"Chiếc bình cao bằng bàn tay của Thạch Nghị, luyện từ bảo cốt, mềm mại óng ánh, phát ánh sáng lành hút đào tiên vào trong.","detail":"Thạch Nghị lấy chiếc bình trắng noãn luyện từ bảo cốt, phát ánh sáng lành hút cây đào tiên vào trong; suýt thu được thì bị Nhóc Tỳ ném tiểu tháp trúng khiến bình nghiêng.","nguon":["@c0168"]},{"id":"thanh-giac-sung-mau-vang","name":"Thánh giác","aliases":["sừng màu vàng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thiếu nữ áo tím"],"trangThai":"dang-co","blurb":"Chiếc sừng màu vàng của thiếu nữ áo tím chuyên phá phù văn, xóa được phù văn của Thần Hầu vương.","detail":"Thánh giác là chiếc sừng màu vàng chuyên phá phù văn; thiếu nữ áo tím dùng nó xóa phù văn của Thần Hầu vương để đoạt một cây đào tiên.","nguon":["@c0168"]},{"id":"luoi-than-li-long","name":"Lưới thần của Li Long","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Li Long"],"trangThai":"dang-co","blurb":"Chiếc lưới thần Li Long lấy ra bao phủ một gốc đào tiên trong cuộc tranh đoạt.","detail":"Li Long dùng lưới thần bọc một gốc đào tiên nhưng bị Thần Hầu bắn kim thần đâm trúng, buông dược bỏ chạy.","nguon":["@c0168"]},{"id":"co-phu-chu-kien","name":"Cổ phù của Chư Kiền","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chư Kiền"],"trangThai":"dang-co","blurb":"Cổ phù của Chư Kiền phát ra sức mạnh thần bí thành chùm ánh sáng bao phủ thánh dược.","detail":"Chư Kiền dùng cổ phù phát ra chùm ánh sáng bao phủ thánh dược để cướp đi, nhưng bị chém đứt đuôi phải chạy.","nguon":["@c0168"]},{"id":"chi-bao-tat-phuong","name":"Chí bảo của Tất Phương","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo","soHuu":["Tất Phương"],"trangThai":"dang-co","blurb":"Bảo cụ giúp Tất Phương chạy thoát khỏi tay Thần Hầu vương sau khi bị đánh nổ nửa người.","detail":"Tất Phương dùng bảo cụ tạo thông đạo màu vàng để nhổ đào tiên; khi bị Thần Hầu đánh nổ nửa người, hắn dựa vào chí bảo này để chạy thoát.","nguon":["@c0168"]},{"id":"cai-ken-tui-can-khon","name":"Cái kén","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Kén trong túi Càn Khôn chứa sinh linh sắp tắt thở, thi được đại trận hô thu đào tiên.","detail":"Cái kén giấu trong túi Càn Khôn của Nhóc Tỳ chứa một sinh linh sắp tắt thở; kén chấn động, thi triển đại trận hô Thu khiến một cây đào tiên bay tới cho Nhóc Tỳ.","nguon":["@c0168"]},{"id":"cai-ken-phat-sang-nhi-ngoc-tu","name":"Chiếc kén phát sáng (kén Nhị Ngốc Tử)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu quý","phamCap":"Không rõ","soHuu":["Hỏa Linh Nhi","Thạch Hạo"],"trangThai":"da-dung","blurb":"Kén lớn phát sáng, bên trong là quái điểu Nhị Ngốc Tử. Tơ kén được ví quý ngang tơ Thiên Tằm — may áo thì bụi trần bất nhiễm, thủy hỏa bất xâm, phòng ngự kinh người.","detail":"Chiếc kén phát sáng nhốt sinh linh quái điểu; sau khi phá kén, Hỏa Linh Nhi sai tên Người phong ấn kéo tơ như xe tơ kéo sợi, cuộn thành quả cầu tơ hào quang bảy màu. Tơ kén được cho là hiếm thấy không thua tơ Thiên Tằm.","nguon":["@c0169"]},{"id":"xich-than-trat-tu","name":"Xích Thần Trật Tự","category":"khac","categoryLabel":"Sức mạnh quy tắc","phamCap":"Quy tắc tiểu thế giới","soHuu":["Tiểu thế giới Thượng Cổ"],"trangThai":"dang-co","blurb":"Sức mạnh quy tắc của tiểu thế giới, luồng hào quang đỏ tươi như máu giống tia chớp, giáng xuống kẻ mở phong ấn.","detail":"Khi cường giả bị phong ấn mở khóa để phản kháng, quy tắc tiểu thế giới cảm ứng và giáng xuống Xích Thần Trật Tự đỏ như máu, cắt kẻ mở phong ấn thành hai đoạn rồi nổ tung hóa thành tro tàn. Đã giết Vũ Côn, Vũ Văn Thành cùng nhiều người tứ đại gia tộc mở phong ấn.","nguon":["@c0171"]},{"id":"soi-day-xich-mau-mau","name":"Sợi dây xích màu máu","cn":"","category":"phap-bao","categoryLabel":"Bảo vật bí ẩn","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Lực lượng bí ẩn trong tiểu thế giới, đủ sức đối kháng bàn tay Nhân Hoàng.","detail":"Một sợi dây xích màu máu xuất hiện từ tiểu thế giới đâm tới bàn tay ánh sáng của Nhân Hoàng như muốn hủy diệt; Nhân Hoàng bắn một chỉ va chạm khiến dây xích thiếu chút nữa đứt rời. Nguồn gốc chưa rõ.","nguon":["@c0172"]},{"id":"than-linh-phap-chi","name":"Thần Linh pháp chỉ","cn":"","category":"phap-bao","categoryLabel":"Pháp chỉ quý giá","phamCap":"Không rõ","soHuu":["Vũ tộc"],"trangThai":"hong","blurb":"Vật quý Vũ tộc dùng, tiếc là bị Nhóc Tỳ phá hoại.","detail":"Vũ tộc hối tiếc đã lãng phí Thần Linh pháp chỉ trong biến cố ở Bách Đoạn sơn.","nguon":["@c0173"]},{"id":"ngoc-dinh-vu-toc","name":"Ngọc đỉnh","cn":"","category":"phap-bao","categoryLabel":"Khí cụ","phamCap":"Không rõ","soHuu":["Vũ tộc"],"trangThai":"dang-co","blurb":"Dụng cụ Vũ tộc chuẩn bị để thu Thái Nhất Chân Thủy vào.","detail":"Vũ tộc chuẩn bị đầy đủ để thu Thái Nhất Chân Thủy vào Ngọc đỉnh nhưng bị Nhóc Tỳ đoạt uống cả bụng.","nguon":["@c0173"]},{"id":"kiem-nguyen-rua-lao-quy","name":"Kiếm nguyền rủa","cn":"","aliases":["Kiếm cho lão quỷ"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đào Dã nguyên lão"],"trangThai":"dang-co","blurb":"Thanh kiếm mang lời nguyền mà Nhóc Tỳ vào Bách Đoạn sơn tìm cho một lão quỷ. Đào Dã chỉ muốn thanh kiếm này, các thứ khác không cần, hai bên thành giao dịch.","detail":"Thanh kiếm nguyền rủa liên quan đến tia hắc khí ẩn nơi xương trán Nhóc Tỳ và lời hứa tìm kiếm cho lão quỷ. Trong chương 174, Đào Dã đề nghị giao dịch chỉ lấy thanh kiếm nguyền rủa, những thứ khác đều không muốn, hai bên thành giao.","nguon":["@c0174"]},{"id":"xich-than-troi-bong-long","name":"Xích thần trói buộc","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Mộ Viêm"],"trangThai":"dang-co","blurb":"Mấy sợi xích thần trói tay chân Bóng Lông treo trước cung điện của lão tổ Lôi đạo.","detail":"Pháp bảo trói buộc của lão tổ Lôi đạo Bổ Thiên các; dùng xích thần trói tay chân Bóng Lông (khỉ lông vàng) treo trước cung điện. Sau khi nhận ra lai lịch cực lớn của con khỉ, lão tổ mở xích thần thả Bóng Lông.","nguon":["@c0175"]},{"id":"thit-dai-bang-di-chung","name":"Thịt Đại Bằng (di chủng Thái Cổ)","category":"khac","categoryLabel":"Bảo dược huyết nhục","phamCap":"Không rõ","soHuu":[],"trangThai":"da-dung","blurb":"Thịt di chủng Thái Cổ hầm trong đỉnh đồng phát sáng hóa bảo dược, dược tính rất mạnh, giúp thân thể thức tỉnh phù văn và tinh khí.","detail":"Cả nhóm nướng và hầm các di chủng Thái Cổ; thịt Đại Bằng vàng hầm trong đỉnh đồng hóa bảo dược phát sáng, dược tính mạnh. Thanh Phong ăn xong thức tỉnh phù văn và đột phá mở Động Thiên thứ hai.","nguon":["@c0176"]},{"id":"thanh-kiem-gay-lao-nhan","name":"Thanh kiếm gãy","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Quỷ gia"],"trangThai":"dang-co","blurb":"Thanh kiếm gãy cắm trên đầu lão nhân kiếm gãy; Nhóc Tỳ nói đã tìm thấy nó và xin đổi lấy bảo thuật cái thế.","detail":"Thanh kiếm gãy cắm trên đầu Quỷ gia. Nhóc Tỳ nói mình đã tìm thấy thanh kiếm gãy và dùng làm điều kiện xin lão nhân dạy vài loại bảo thuật cái thế.","nguon":["@c0176"]},{"id":"kim-giao-tien","name":"Kim Giao tiễn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Pháp bảo Nhóc Tỳ lấy ra định chém Quỷ gia nhưng bị một tầng ánh sáng cản lại.","detail":"Nhóc Tỳ lấy Kim Giao tiễn ra định chém Quỷ gia trong lúc phản kháng, nhưng bị một tầng ánh sáng bảo hộ trên người lão cản lại vô hiệu.","nguon":["@c0177"]},{"id":"khoi-xuong-nguyen-thuy-dai-bang","name":"Khối xương nguyên thủy của Đại Bằng","cn":"","category":"khac","categoryLabel":"Thánh cốt / di vật","phamCap":"Đặc biệt (phù văn chưa tiêu tán)","soHuu":[],"trangThai":"khong-ro","blurb":"Khối xương nguyên thủy của Đại Bằng trong bảo khố Tàng Kinh các, phù văn vẫn chưa tiêu tán; Kim Tuyền Ba Văn công do một tiền bối ngộ ra từ đó.","detail":"Ghi chép trong cốt thư cho thấy trong bảo khố này có một khối xương nguyên thủy của Đại Bằng, rất đặc biệt, phù văn vẫn chưa tiêu tán. Thạch Hạo phát hiện và kích động truy hỏi vị trí; chương chưa tiết lộ nơi cất giữ.","nguon":["@c0178"]},{"id":"bao-vat-than-tinh-khoi-phuc-te-linh","name":"Bảo vật thần tính","cn":"","category":"khac","categoryLabel":"Bảo vật","phamCap":"Thần tính","soHuu":[],"trangThai":"dang-co","blurb":"Bảo vật thần tính mà Bổ Thiên các đang chuẩn bị để giúp Tế Linh khôi phục sức sống.","detail":"Bổ Thiên các đang chuẩn bị bảo vật thần tính để khôi phục Tế Linh; chỗ Tế Linh đang bị phong tỏa, không ai vào được.","nguon":["@c0178"]},{"id":"khoi-kim-cot-that-lac","name":"Khối kim cốt (thất lạc)","aliases":["Côn Bằng cốt","mảnh xương Côn Bằng"],"category":"nguyen-lieu","categoryLabel":"Bảo cốt / Cốt thư","phamCap":"Chí bảo","soHuu":[],"trangThai":"mat","blurb":"Vật hiếm hai ngàn năm mới xuất hiện, chỉ lộ diện ba lần, được cho là đã thông linh và tự chạy trốn; nguồn gốc Kim Tuyền Ba Văn công.","detail":"Khối kim cốt là vật cực kỳ hiếm có, lần cuối xuất hiện đã hai ngàn năm trước, cả thảy chỉ mới lộ diện ba lần. Có người từng lĩnh hội phù văn trên đó rồi sáng chế ra Kim Tuyền Ba Văn công. Ông lão canh cửa Tàng Kinh các nghi khối cốt đã thông linh, tự chạy trốn giống nhiều bảo thuật trấn giáo Thượng Cổ đã không cánh mà bay. Nếu tìm lại và lĩnh hội toàn bộ sẽ là bảo thuật kinh khủng thế gian.","nguon":["@c0179"]},{"id":"hai-khoi-cot-thu-con-lai","name":"Hai khối cốt thư còn lại","category":"nguyen-lieu","categoryLabel":"Cốt thư","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Xương màu vàng nhạt rạn nứt, bề mặt có chữ li ti, dùng lĩnh ngộ Kim Tuyền Ba Văn công.","detail":"Hai khối cốt thư còn lại trong Tàng Kinh các, xương màu vàng nhạt đã rạn nứt, bề mặt có phù văn chữ li ti. Nhóc Tỳ đọc chúng để lĩnh ngộ Kim Tuyền Ba Văn công (quyển trung và quyển hạ).","nguon":["@c0179"]},{"id":"loi-kiep-dich","name":"Lôi Kiếp dịch","category":"dan-duoc","categoryLabel":"Bảo dịch","phamCap":"Vô giá","soHuu":["Mộ Viêm"],"trangThai":"khac","blurb":"Chất lỏng màu tím vô giá, do Mộ Viêm bắt thần lôi tế luyện thành, một giọt đủ giúp lột xác tiến bộ.","detail":"Lôi Kiếp dịch là chất lỏng màu tím được xưng có linh tính mạnh nhất, vô giá; do lão tổ Mộ Viêm bắt thần lôi tế luyện thành và đã trả giá lớn để có được. Một giọt đủ giúp lột xác tiến bộ. Mộ Viêm hiến một giọt trong sự kiện cứu Tế Linh.","nguon":["@c0179","@c0187"]},{"id":"khoi-huyet-nhuc-cua-than","name":"Khối huyết nhục của Thần","category":"nguyen-lieu","categoryLabel":"Thần vật","phamCap":"Thần cấp","soHuu":[],"trangThai":"da-dung","blurb":"Khối huyết nhục khô héo đen xì có sức mạnh thần tính mạnh mẽ, do Các chủ hiến cứu Tế Linh.","detail":"Một khối huyết nhục của Thần khô héo đen xì nhưng hàm chứa sức mạnh thần tính mạnh mẽ. Đào Dã giải thích đó là huyết nhục của Thần. Các chủ Bổ Thiên các hiến trong sự kiện phục sinh Tế Linh, cho thấy nội tình sâu và mối liên hệ với Thần thời Thượng Cổ.","nguon":["@c0179"]},{"id":"dat-lam-tinh","name":"Đất Lam Tinh","aliases":["đất Lam Linh"],"category":"nguyen-lieu","categoryLabel":"Thần vật","phamCap":"Không rõ","soHuu":[],"trangThai":"da-dung","blurb":"Đất có hào quang xanh lam từ Lam Tinh vực ngoại rơi xuống, sinh mệnh khí tức cường đại.","detail":"Một lão tổ dùng cổ đỉnh đổ ra đất Lam Tinh (đất Lam Linh) từ Lam Tinh vực ngoại, có hào quang xanh lam và sinh mệnh khí tức cường đại, dùng hiến tế cứu Tế Linh.","nguon":["@c0179"]},{"id":"co-dinh-lao-to","name":"Cổ đỉnh","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Cổ đỉnh một lão tổ dùng để đổ ra đất Lam Tinh trong sự kiện cứu Tế Linh.","detail":"Một chiếc cổ đỉnh do một lão tổ Bổ Thiên các dùng đổ ra đất Lam Tinh trong sự kiện hiến tế phục sinh Tế Linh.","nguon":["@c0179"]},{"id":"khoi-kim-cot","name":"Khối kim cốt","cn":"","category":"khac","categoryLabel":"Cốt thư / bảo vật","phamCap":"Ngang bảo thuật trấn giáo","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","aliases":["kim cốt","khối xương màu vàng","xương Côn Bằng","Côn Bằng cốt","mảnh xương Côn Bằng"],"blurb":"Khối xương màu vàng lấp lánh phù văn, linh tính hơn xa bảo cụ, chôn dưới rễ Tế Linh và được tặng cho Nhóc Tỳ.","detail":"Tế Linh mọc mầm non thâm nhập lòng đất quấn lấy khối kim cốt lấp lánh phù văn đưa lên tặng Nhóc Tỳ, nói nó không kém bảo thuật trấn giáo. Nhóc Tỳ tin nắm được khối kim cốt sẽ giúp bảo thuật Côn Bằng lột xác về chất, đồng thời nghi ngờ dưới rễ Tế Linh còn chôn nhiều cốt thư và thần thông trấn giáo thất lạc của Bổ Thiên các.","nguon":["@c0180"]},{"id":"than-nguyet-mau-vang-ngo-dao","name":"Thần nguyệt màu vàng","category":"khac","categoryLabel":"Biểu hiện ngộ đạo","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Biểu hiện ngộ đạo của Nhóc Tỳ: thần nguyệt vàng đặt vào Động Thiên có Ma cầm, hóa quả trứng phủ phù văn xanh thai nghén Thần Bằng.","detail":"Trong cảnh ngộ đạo, Nhóc Tỳ đặt thần nguyệt màu vàng vào một tòa Động Thiên có Ma cầm; dung nham dâng lên, thần nguyệt hóa thành quả trứng phủ phù văn xanh, thai nghén ra một Thần Bằng chí cường lao ra đứng sừng sững bên cạnh nó.","nguon":["@c0181"]},{"id":"mau-sung-rong-kim-tinh-long-giac-su","name":"Máu sừng rồng (sừng Kim Tình Long Giác Sư)","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bảo dược đại bổ","soHuu":["Thanh Phong"],"trangThai":"da-dung","blurb":"Máu tươi trong sừng rồng của Kim Tình Long Giác Sư, bảo dược đại bổ uống khi còn nóng.","detail":"Khi sừng rồng gãy phun máu tươi còn nóng, Nhóc Tỳ hứng vào bình ngọc cho Thanh Phong uống làm bảo dược, tự mình không uống.","nguon":["@c0182"]},{"id":"phu-bai-ha-u-vu","name":"Phù bài của Hạ U Vũ","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thanh Phong"],"trangThai":"dang-co","blurb":"Tấm phù bài Hạ U Vũ từng cho Nhóc Tỳ ở biên giới phía tây Thạch quốc; Nhóc Tỳ đã đưa cho Thanh Phong.","detail":"Tấm phù bài mà Hạ U Vũ cho Nhóc Tỳ khi gặp nhau ở biên giới phía tây Thạch quốc lúc nó xông vào Đại Hoang, sau nó chuyển cho Thanh Phong.","nguon":["@c0182"]},{"id":"bon-mieng-tan-cot-vang","name":"Bốn miếng tàn cốt vàng","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Bảo cốt di chủng chí cường","soHuu":["Tứ đại thiếu niên cường giả (Trục Lộc học viện)"],"trangThai":"dang-co","blurb":"Xương của di chủng chí cường mà tứ đại cường giả Trục Lộc học viện mang theo, kết hợp thành bảo cụ và sát trận.","detail":"Bốn miếng tàn cốt vàng do tứ đại thiếu niên cường giả Trục Lộc học viện mang theo, kết hợp thành bằng trảo, cánh thần, kiếm thần, linh vũ chim bằng và một tòa sát trận đối phó Nhóc Tỳ; bị vòng xoáy vàng của Nhóc Tỳ hút phù văn khiến trận pháp thất bại.","nguon":["@c0184"]},{"id":"than-chung-te-linh","name":"Thần chủng (của Tế Linh)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Thần chủng","soHuu":["Tế Linh"],"trangThai":"dang-co","blurb":"Thứ mà lão tổ Bổ Thiên các xin Tế Linh lưu lại để tái sinh sau khi tọa hóa.","detail":"Hạt giống tái sinh của Tế Linh; lão tổ Bổ Thiên các xin lưu lại để dây leo có thể sống lại. Tế Linh nói trăm nghìn năm sau có thể có dây leo tương tự nhưng đã không còn là nó nữa. Nhiều thế lực như hung cầm ngoài vạn dặm nhòm ngó muốn chiếm đoạt.","nguon":["@c0185"]},{"id":"long-dai-hong-dieu-di-chung","name":"Lông Đại Hồng Điểu (di chủng)","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Di chủng có thần tính","soHuu":["Hỏa Linh Nhi"],"trangThai":"dang-co","blurb":"Lông đỏ tươi có bảo quang, ẩn chứa thần tính, bị vặt về làm quạt.","detail":"Sau khi Đại Hồng Điểu bị vặt sạch lông đen bên ngoài, bên trong lộ ra màu đỏ tươi rực rỡ có bảo quang, ẩn chứa thần tính. Hỏa Linh Nhi cho vặt về làm quạt vì coi là di chủng; lông có độc, chảy máu.","nguon":["@c0186"]},{"id":"loi-kiep-dich-than-dich","name":"Lôi Kiếp Dịch","aliases":["Thần dịch"],"category":"khac","categoryLabel":"Thần dịch","phamCap":"Bảo vật vô giá","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Thần dịch sinh ra từ sinh cơ thai nghén trong Lôi Điện Cửu Thiên, sinh cơ và linh tính không gì sánh, thích hợp ngộ đạo xông quan.","detail":"Sinh cơ thai nghén trong Lôi Điện Cửu Thiên, hình thành đoàn khí tím co rút hóa thành một giọt chất lỏng. Có sinh cơ và linh tính không gì sánh, thích hợp ngộ đạo và xông quan, là bảo vật vô giá; Mộ Viêm xưa tốn nhiều năm mới được một giọt. Ông luyện hóa được một giọt đựng vào bình ngọc rồi nhường cho Nhóc Tỳ hấp thu để xây căn cơ Lôi Đạo.","nguon":["@c0188"]},{"id":"hau-nhi-tuu-linh-duoc","name":"Hầu Nhi Tửu","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Chí bảo chữa thương","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Rượu do mấy chục loại linh dược ủ lại, thần hiệu điều trị thương thế; Nhóc Tỳ mời Mộ Viêm uống để khôi phục.","detail":"Rượu do mấy chục loại linh dược ủ lại với nhau, có thần hiệu điều trị thương thế vô cùng hiệu quả. Nhóc Tỳ lấy làm chí bảo chữa thương mời Mộ Viêm uống để khôi phục sau khi liều mạng chiết Lôi Kiếp Dịch.","nguon":["@c0188"]},{"id":"than-chung-luu-lai-te-linh","name":"Thần Chủng","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Thần vật","soHuu":["Tế Linh"],"trangThai":"dang-co","blurb":"Hạt giống Tế Linh (Thần Đằng) quyết định lưu lại để tương lai bảo vệ Bổ Thiên Các tái sinh.","detail":"Khi sinh mệnh sắp cạn, Tế Linh quyết định lưu lại Thần Chủng — hạt giống của Thần Đằng — để tương lai bảo vệ Bổ Thiên Các tái sinh. Nó tuyên bố chỉ cần một người còn sống thì Bổ Thiên Các không tính là diệt vong, sẽ tắm lửa mà sống lại.","nguon":["@c0189"]},{"id":"than-chung-lao-dang","name":"Thần Chủng","cn":"神种","category":"phap-bao","categoryLabel":"Chí bảo","phamCap":"Chí bảo","soHuu":["Tế Linh"],"trangThai":"dang-co","blurb":"Tinh hoa cả một đời của Lão Đằng, chí bảo mà ba đại Chí Cường Giả tranh đoạt; điều kiện đưa ra Thần Chủng đổi lấy việc bảo hộ Bổ Thiên Các.","detail":"Thần Chủng là vị trí tinh hoa cả một đời của Lão Đằng. Ba Chí Cường Giả (sinh linh Nghi Sơn, Thôn Thiên Tước, Cùng Kỳ) hội tụ tại Bổ Thiên Các đòi Thần Chủng, hứa bảo hộ Thánh Địa. Khi bị bủa vây cướp đoạt, Thần Chủng bị tổn hại khiến máu tươi văng tung tóe, cho thấy nó mạnh mẽ cỡ nào.","nguon":["@c0190"]},{"id":"loi-than-chuy-mo-viem","name":"Lôi Thần Chùy","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Mộ Viêm"],"trangThai":"dang-co","blurb":"Chùy màu tím phát sáng của Lôi tổ Mộ Viêm, bổ ra luồng tia chớp lớn khi giao chiến.","detail":"Pháp bảo lôi đạo của Lôi tổ Mộ Viêm dùng khi chống lão tổ Thác Bạt Gia, chùy tím phát sáng bổ ra tia chớp mạnh.","nguon":["@c0190"]},{"id":"chien-mau-rang-nanh","name":"Chiến mâu răng nanh","category":"than-khi","categoryLabel":"Bảo cụ","phamCap":"Không rõ","soHuu":["Bạch Hổ"],"trangThai":"hong","blurb":"Mười mấy thanh chiến mâu trắng bạc tế luyện từ răng nanh của Bạch Hổ, bị Liễu Lão chặt đứt.","detail":"Chiến mâu răng nanh là mười mấy thanh chiến mâu trắng bạc được tế luyện từ răng nanh của Bạch Hổ, làm bảo cụ chiến đấu. Trong trận với Liễu Lão, chúng bị chém đứt.","nguon":["@c0191"]},{"id":"kiem-gay-quy-gia","name":"Kiếm Gãy","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nhóc Tỳ","Quỷ Gia"],"trangThai":"Trong tay Nhóc Tỳ","blurb":"Thanh kiếm gãy ẩn linh Quỷ Gia, phát sáng khi triệu xuất chủ nhân.","detail":"Kiếm Gãy nằm trong tay Nhóc Tỳ. Khi Nhóc Tỳ bi thương mãnh liệt cầm kiếm xung phong, Kiếm Gãy phát sáng và triệu xuất Quỷ Gia — lão già tóc bù xù đầu cắm cổ kiếm chảy máu đen ẩn bên trong. Quỷ Gia nhận Kiếm Gãy, mê man rồi tỉnh, dùng nó vọt lên chín tầng trời chém đứt móng vuốt Thôn Thiên Tước.","nguon":["@c0192"]},{"id":"tieu-thap-nhoc-ty","name":"Tiểu Tháp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"Trong tay Nhóc Tỳ","blurb":"Bảo tháp nhỏ Nhóc Tỳ một tay cầm cùng Kiếm Gãy khi xung phong.","detail":"Tiểu Tháp là pháp bảo được Nhóc Tỳ cầm một tay cùng với Kiếm Gãy tay còn lại khi bi thương mãnh liệt xung phong ra trận, dù không thể bay lên chín tầng trời.","nguon":["@c0192"]},{"id":"cung-ten-bac-lang-thien-hau","name":"Cung tên bạc Lăng Thiên Hầu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lăng Thiên Hầu"],"trangThai":"Đang dùng","blurb":"Cung tên bạc rực rỡ, mũi tên tự đổi hướng rượt địch, bắn nổ quạ Thái Cổ.","detail":"Pháp bảo cung của Lăng Thiên Hầu. Mũi tên màu bạc rực rỡ bắn ra tự đổi hướng rượt theo địch, phá tan lửa đen của con quạ đen Thái Cổ Cầm Tộc rồi bắn thủng thân thể con quạ khiến nó nổ tung chia năm xẻ bảy.","nguon":["@c0192"]},{"id":"bao-an-toc-chu-ky-son","name":"Bảo ấn Tộc chủ Kỳ Sơn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tộc chủ Kỳ Sơn"],"trangThai":"Đang dùng","blurb":"Bảo ấn hóa lớn hơn núi đè xuống nghiền nát sinh linh địch.","detail":"Pháp bảo ấn của Tộc chủ Kỳ Sơn. Khi ông lão nâng bảo ấn lên, nó hóa lớn hơn cả ngọn núi rồi đè xuống nghiền nát các sinh linh địch phía dưới, trợ chiến cho Tịnh Thổ Bổ Thiên Các.","nguon":["@c0192"]},{"id":"kiem-xanh-biec-mai-rang-thu","name":"Kiếm xanh biếc mài từ răng thú","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão quái vật cấp lão tổ"],"trangThai":"Đã bị hủy","blurb":"Kiếm xanh mài từ răng con thú lâu năm, mũi nhọn xuyên thấu vạn vật, bị Chiến Vương búng nát.","detail":"Binh khí tế luyện cả đời của lão quái vật cấp lão tổ có đại thù với Bổ Thiên Các, được mài từ răng của một con thú lâu năm không tên. Mũi nhọn không gì không xuyên, cắt được cả núi. Lão quái vật phun thanh kiếm đâm tới Chiến Vương, nhưng Chiến Vương điểm liên tiếp mười ngón tay khiến thanh kiếm xanh biếc rạn nứt và bị ngón tay búng nát.","nguon":["@c0192"]},{"id":"kim-cot-phien","name":"Kim Cốt Phiên","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Sinh linh hình người Nam Vẫn Thần Sơn"],"trangThai":"dang-co","blurb":"Cây cờ bằng xương màu vàng, bảo cụ trong tay sinh linh hình người của Nam Vẫn Thần Sơn.","detail":"Bảo cụ màu vàng dạng cây cờ làm bằng xương, được sinh linh hình người Nam Vẫn Thần Sơn dùng trong trận tranh đoạt Thần Chủng ở Tịnh Thổ.","nguon":["@c0193"]},{"id":"co-kiem-cam-dau-thuy-to","name":"Cổ kiếm cắm đầu Thủy Tổ","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Một cây cổ kiếm cắm xuyên đầu Thủy Tổ khiến xương sọ nứt, máu đen chảy, không thể rút ra.","detail":"Trong trận tử chiến trên chín tầng trời, đầu Thủy Tổ tóc xám bị một cây cổ kiếm cắm xuyên khiến xương sọ nứt, máu đen chảy — đây là nguồn gốc trạng thái nguy kịch của ông, ông không thể rút kiếm ra.","nguon":["@c0194"]},{"id":"cot-phien-hoang-kim-nam-van","name":"Cốt phiên hoàng kim","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Sinh linh hình người Nam Vẫn Thần Sơn"],"trangThai":"hong","blurb":"Cốt phiên hoàng kim của cường giả Thần Sơn Nam Vẫn, rung động bầu trời, bị Thủy Tổ chặt đứt một đoạn.","detail":"Sinh linh hình người Thần Sơn Nam Vẫn cầm cốt phiên hoàng kim rung động bầu trời khi vây công Bổ Thiên các; trong trận Thủy Tổ chặt đứt một đoạn cốt phiên cùng vài ngón tay của kẻ cầm.","nguon":["@c0194"]},{"id":"xe-chien-nhan-hoang","name":"Xe chiến cổ xưa Nhân Hoàng","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nhân Hoàng","Hỏa Linh Nhi"],"trangThai":"dang-co","blurb":"Xe chiến cổ xưa của Nhân Hoàng Hỏa Quốc, bùng sáng như thái dương, phong ấn núi và bao phủ đưa môn nhân Bổ Thiên các đi xa.","detail":"Chở Hỏa Linh Nhi và Nhân Hoàng, khi bùng sáng như thái dương thì phù văn phong ấn cả ngọn núi, bao phủ mấy trăm môn nhân Bổ Thiên các đưa đi khỏi vòng vây.","nguon":["@c0194"]},{"id":"vong-than-nghi-son","name":"Vòng thần sau đầu","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Cường giả Nghi Sơn"],"trangThai":"hong","blurb":"Vòng thần sau đầu của cường giả Nghi Sơn, biến lớn như mặt trời, bị Thủy Tổ chém đứt.","detail":"Cường giả Nghi Sơn (Thái Cổ Thần Sơn) mang vòng thần sau đầu biến lớn như mặt trời trong trận vây công; bị kiếm gãy của Thủy Tổ chém đứt.","nguon":["@c0194"]},{"id":"co-u-lan","name":"Cỏ U Lan","category":"nguyen-lieu","categoryLabel":"Vật phẩm truy tung","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Loại cỏ có mùi thơm dai dẳng mấy ngày, dùng để lần theo dấu vết.","detail":"Tứ đại gia tộc bôi cỏ U Lan lên người Nhóc Tỳ; mùi thơm dính dai dẳng mấy ngày giúp chúng lần theo mùi mà truy sát, dù nó đã cải trang bằng bảo thuật Bóng Lông vẫn bị nhận ra.","nguon":["@c0195"]},{"id":"than-vat-lac-hoang-linh","name":"Thần vật Lạc Hoàng lĩnh","aliases":["sinh linh chưa rõ"],"category":"khac","categoryLabel":"Bảo vật sống","phamCap":"Vô giá","soHuu":[],"trangThai":"dang-co","blurb":"Sinh linh quý hiếm như thánh dược hóa hình xuất hiện ở Lạc Hoàng lĩnh, bị Vũ tộc điên cuồng truy bắt.","detail":"Một sinh linh sống quý hiếm mấy trăm năm chưa chắc có một con, quý hơn mấy chục cây linh dược cộng lại, tựa như thánh dược hóa hình. Đã xuất hiện ở Lạc Hoàng lĩnh khoảng hai tháng; Vũ Vương ra lệnh cho cả tộc điên cuồng truy bắt để dâng lên hoàng gia. Chân dạng chưa lộ rõ.","nguon":["@c0196"]},{"id":"vang-den-lac-hoang-linh","name":"Vàng đen","category":"nguyen-lieu","categoryLabel":"Khoáng vật","phamCap":"Chưa rõ","soHuu":[],"trangThai":"dang-co","blurb":"Khoáng vật quý là sản vật của mỏ tại Lạc Hoàng lĩnh.","detail":"Mỏ vàng đen là một trong những sản vật trọng yếu của Lạc Hoàng lĩnh, cùng với vườn linh dược và dãy núi thụy thú, khiến nơi này trở thành lãnh địa giàu có mà nhóm Nhóc Tỳ nhắm cướp.","nguon":["@c0196"]},{"id":"bat-tran-ke","name":"Bát Trân Kê","category":"linh-khi","categoryLabel":"Linh vật","phamCap":"Thần trân Thái Cổ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Con gà đất cao nửa mét, lông vàng đất, nguyên liệu một trong tám món bát trân thời Thái Cổ mà Thần Linh cũng thèm.","detail":"Thân ẩn linh huyết là vị thuốc chỉ dưới thánh dược; mỗi tháng đẻ một quả trứng dược tính ngang linh dược; có thể lên trời xuống đất, xuyên đất, câu thông đại địa. Mấy trăm năm khó gặp một con, cả hoàng tộc Thạch quốc chỉ có một con. Bị Nhóc Tỳ bắt về nuôi cho Thạch thôn.","nguon":["@c0197"]},{"id":"linh-duoc-lac-hoang-linh","name":"Linh dược Lạc Hoàng lĩnh","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Linh dược","soHuu":["Bóng Lông","Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Mười một cây linh dược tỏa sáng lấp lánh Bóng Lông trộm về từ Lạc Hoàng lĩnh; mỗi linh sơn chỉ sinh một cây.","detail":"Bóng Lông chỉ đi một chuyến trộm được mười một cây, phá hoại tan tành cả lĩnh.","nguon":["@c0197"]},{"id":"nhan-sam-tuyet-ngoc","name":"Nhân sâm Tuyết Ngọc","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Linh dược","soHuu":["Nhóc Tỳ"],"trangThai":"da-dung","blurb":"Cây nhân sâm trắng bóng nõn nà tỏa hòa quang thần dị, Nhóc Tỳ tặng cháu nhỏ Đại Tráng làm lễ ra mắt.","detail":"Dặn giữ tới khi Trúc Cơ mới dùng.","nguon":["@c0199"]},{"id":"dat-than-bat-lao-tuyen","name":"Đất thần Bất Lão Tuyền","category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"Thần thổ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Bùn cát vàng lấy dưới đáy Bất Lão Tuyền nắm giữ thần tính bất hủ, dùng bón cho linh dược.","detail":"Giúp linh dược sinh trưởng tốt, tụ tinh hoa thiên địa; Nhóc Tỳ mang về cải tạo linh khí Thạch thôn thành thần thổ.","nguon":["@c0199"]},{"id":"huyet-nhuc-toan-nghe","name":"Huyết nhục Toan Nghê","category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"Huyết nhục dị thú","soHuu":["Thạch thôn"],"trangThai":"da-dung","blurb":"Huyết nhục dị thú Toan Nghê giúp đám thiếu niên và tráng niên Thạch thôn tăng tiến cảnh giới.","detail":"Cùng bảo huyết Tế Linh giúp Thạch Lâm Hổ, Thạch Phi Giao lên Động Thiên cảnh; Đại Tráng, Nhị Mãnh, Bì Hầu vào Bàn Huyết cảnh.","nguon":["@c0199"]},{"id":"bat-lao-than-tuyen-than-tho","name":"Bất Lão Thần Tuyền","aliases":["thần thổ Bách Đoạn sơn"],"category":"nguyen-lieu","categoryLabel":"Thần thổ","phamCap":"Thần thổ bất hủ","soHuu":["Liễu Thần"],"trangThai":"da-dung","blurb":"Sáu túi da thú lớn bùn cát màu vàng lấy từ Bách Đoạn sơn, thai nghén thần tính bất hủ, tái hiện cảnh ao thần Bách Thảo viên.","detail":"Nhóc Tỳ dâng hết cho Liễu Thần dùng phân giải thần tính bất hủ để hồi phục, giúp cành cây càng lớn mạnh không cần tẩm bổ thần thổ nữa.","nguon":["@c0200"]},{"id":"thit-di-chung-thai-co","name":"Thịt di chủng Thái Cổ","category":"dan-duoc","categoryLabel":"Đại dược","phamCap":"Đại dược","soHuu":["Nhóc Tỳ","Thạch thôn"],"trangThai":"da-dung","blurb":"Thịt các di chủng Thái Cổ (Kim Sí Đại Bằng, Bạch Hổ...) ba bốn mươi con, ăn một miếng có hy vọng đột phá.","detail":"Hơn nửa săn ở Bách Đoạn sơn, nửa còn lại khi chiến ở Bổ Thiên các; hầm với nấm Đầu Khỉ, cao hổ từ Bạch Hổ Thái Cổ. Có người đột phá ngay tại tiệc.","nguon":["@c0200"]}]};
